type DraftAnnonceTypeProfile = {
  kind: HektorPropertyProfileKind
  surfaceMode: 'habitable' | 'terrain' | 'garage' | 'none'
  showRooms: boolean
  showBedrooms: boolean
  showLevels: boolean
  showGarageCount: boolean
  showGardenPool: boolean
  showExposure: boolean
  showView: boolean
  showInteriorDetails: boolean
  showOutdoorDetails: boolean
  showCoproDetails: boolean
}

function draftAnnoncePropertyGroupForTypeId(id: string): (typeof draftAnnoncePropertyGroups)[number] {
  return draftAnnoncePropertyGroups.find((group) => group.types.some((type) => type.id === id)) ?? draftAnnoncePropertyGroups[1]
}

function draftAnnonceTypeOptionsForGroup(groupId: DraftAnnoncePropertyGroupId) {
  return draftAnnoncePropertyTypes.filter((item) => item.group === groupId)
}

function draftAnnoncePropertyProfileKindForTypeId(id: string): HektorPropertyProfileKind {
  const group = draftAnnoncePropertyGroupForTypeId(id).id
  if (group === 'terrains') return 'land'
  if (id === '15' || id === '16' || id === '29') return 'garage'
  if (id === '21') return 'building'
  if (group === 'maisons' || id === '17') return 'house'
  if (group === 'autres') return 'other'
  return 'apartment'
}

function draftAnnoncePropertyProfileKindFromText(value: string | null | undefined): HektorPropertyProfileKind {
  const normalized = normalizeDraftAnnonceScanText(value)
  if (!normalized) return 'apartment'
  if (normalized.includes('terrain')) return 'land'
  if (normalized.includes('garage') || normalized.includes('parking') || normalized.includes('cave')) return 'garage'
  if (normalized.includes('immeuble')) return 'building'
  if (normalized.includes('maison') || normalized.includes('villa') || normalized.includes('propriete') || normalized.includes('ferme') || normalized.includes('mas') || normalized.includes('chalet')) return 'house'
  if (normalized.includes('appartement') || normalized.includes('studio') || normalized.includes('duplex') || normalized.includes('loft')) return 'apartment'
  return 'other'
}

function draftAnnonceTypeProfileFromKind(kind: HektorPropertyProfileKind): DraftAnnonceTypeProfile {
  if (kind === 'land') {
    return {
      kind,
      surfaceMode: 'terrain',
      showRooms: false,
      showBedrooms: false,
      showLevels: false,
      showGarageCount: false,
      showGardenPool: false,
      showExposure: false,
      showView: false,
      showInteriorDetails: false,
      showOutdoorDetails: false,
      showCoproDetails: false,
    }
  }
  if (kind === 'garage') {
    return {
      kind,
      surfaceMode: 'garage',
      showRooms: false,
      showBedrooms: false,
      showLevels: false,
      showGarageCount: false,
      showGardenPool: false,
      showExposure: false,
      showView: false,
      showInteriorDetails: false,
      showOutdoorDetails: false,
      showCoproDetails: false,
    }
  }
  if (kind === 'building') {
    return {
      kind,
      surfaceMode: 'habitable',
      showRooms: false,
      showBedrooms: false,
      showLevels: false,
      showGarageCount: false,
      showGardenPool: false,
      showExposure: false,
      showView: false,
      showInteriorDetails: false,
      showOutdoorDetails: true,
      showCoproDetails: false,
    }
  }
  if (kind === 'house') {
    return {
      kind,
      surfaceMode: 'habitable',
      showRooms: true,
      showBedrooms: true,
      showLevels: true,
      showGarageCount: true,
      showGardenPool: true,
      showExposure: true,
      showView: true,
      showInteriorDetails: true,
      showOutdoorDetails: true,
      showCoproDetails: false,
    }
  }
  if (kind === 'other') {
    return {
      kind,
      surfaceMode: 'habitable',
      showRooms: false,
      showBedrooms: false,
      showLevels: false,
      showGarageCount: false,
      showGardenPool: false,
      showExposure: false,
      showView: false,
      showInteriorDetails: false,
      showOutdoorDetails: false,
      showCoproDetails: false,
    }
  }
  return {
    kind,
    surfaceMode: 'habitable',
    showRooms: true,
    showBedrooms: true,
    showLevels: true,
    showGarageCount: true,
    showGardenPool: false,
    showExposure: true,
    showView: true,
    showInteriorDetails: true,
    showOutdoorDetails: true,
    showCoproDetails: true,
  }
}

function draftAnnonceTypeProfile(id: string): DraftAnnonceTypeProfile {
  return draftAnnonceTypeProfileFromKind(draftAnnoncePropertyProfileKindForTypeId(id))
}

function draftAnnoncePropertyTypeLabel(id: string) {
  return draftAnnoncePropertyTypes.find((item) => item.id === id)?.label ?? 'Appartement'
}

function normalizeDraftAnnonceScanText(value: string | null | undefined) {
  return (value ?? '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .trim()
    .toLowerCase()
    .replace(/\s+/g, ' ')
}

function draftAnnoncePropertyTypeIdFromLabel(value: string | null | undefined) {
  const normalized = normalizeDraftAnnonceScanText(value)
  if (!normalized) return ''
  const legacyMatches: Array<{ id: string; labels: string[] }> = [
    { id: '15', labels: ['parking garage', 'garage parking'] },
    { id: '21', labels: ['immeuble'] },
    { id: '2', labels: ['appartement meuble'] },
    { id: '1', labels: ['maison meublee'] },
  ]
  const legacy = legacyMatches.find((item) => item.labels.some((label) => normalized === label || normalized.includes(label)))
  if (legacy) return legacy.id
  const direct = draftAnnoncePropertyTypes.find((item) => normalizeDraftAnnonceScanText(item.label) === normalized)
  if (direct) return direct.id
  return draftAnnoncePropertyTypes.find((item) => normalized.includes(normalizeDraftAnnonceScanText(item.label)) || normalizeDraftAnnonceScanText(item.label).includes(normalized))?.id ?? ''
}

function draftAnnonceScanValue(scan: DraftAnnonceSheetScanPayload, key: keyof DraftAnnonceSheetScanPayload['fields']) {
  return scan.fields[key]?.value?.trim() ?? ''
}

function draftAnnonceScanFilledCount(scan: DraftAnnonceSheetScanPayload) {
  return Object.values(scan.fields).filter((field) => field.value?.trim()).length
}

