function hektorActionJobTitle(job: ConsoleJob) {
  const payload = job.payload_json ?? {}
  const result = job.result_json ?? {}
  const matterportLabel = matterportJobActionLabel(job.job_type)
  if (matterportLabel) {
    const modelName = typeof payload.matterport_name === 'string' && payload.matterport_name.trim() ? payload.matterport_name.trim() : null
    const modelId = typeof payload.matterport_model_id === 'string' && payload.matterport_model_id.trim() ? payload.matterport_model_id.trim() : null
    return [matterportLabel, modelName ?? modelId].filter(Boolean).join(' - ')
  }
  const documentName = typeof payload.document_name === 'string' && payload.document_name.trim()
    ? payload.document_name.trim()
    : typeof payload.original_filename === 'string' && payload.original_filename.trim()
      ? payload.original_filename.trim()
      : typeof payload.document_label === 'string' && payload.document_label.trim()
        ? payload.document_label.trim()
        : null
  if (job.job_type === 'delete_hektor_annonce') {
    return `Suppression ${job.hektor_annonce_id ?? payload.hektor_annonce_id ?? ''}`.trim()
  }
  if (job.job_type === 'archive_hektor_annonce') {
    return `Archivage ${job.hektor_annonce_id ?? payload.hektor_annonce_id ?? ''}`.trim()
  }
  if (job.job_type === 'restore_hektor_annonce') {
    return `Desarchivage ${job.hektor_annonce_id ?? payload.hektor_annonce_id ?? ''}`.trim()
  }
  if (job.job_type === 'change_hektor_annonce_status') {
    return `Statut ${hektorStatusTargetLabel(String(payload.target_status ?? ''))} ${job.hektor_annonce_id ?? payload.hektor_annonce_id ?? ''}`.trim()
  }
  if (job.job_type === 'delete_document_from_hektor') {
    return documentName ? `Suppression ${documentName}` : 'Suppression document'
  }
  if (job.job_type === 'upload_document_to_hektor') {
    return documentName ? `Ajout ${documentName}` : 'Ajout document Hektor'
  }
  if (job.job_type === 'upload_hektor_photo') {
    return documentName ? `Ajout photo ${documentName}` : 'Ajout photo Hektor'
  }
  if (job.job_type === 'prepare_document_cloud') {
    return documentName ? `Preparation ${documentName}` : 'Preparation document'
  }
  if (job.job_type === 'prepare_archived_annonce_detail') {
    return `Detail archive ${job.hektor_annonce_id ?? payload.hektor_annonce_id ?? ''}`.trim()
  }
  if (job.job_type === 'prepare_historical_annonce_detail') {
    return `Detail Vendu/Clos ${job.hektor_annonce_id ?? payload.hektor_annonce_id ?? ''}`.trim()
  }
  if (job.job_type === 'update_hektor_annonce_fields') {
    return `Modification ${job.hektor_annonce_id ?? payload.hektor_annonce_id ?? ''}`.trim()
  }
  if (job.job_type === 'create_hektor_mandat_auto_number') {
    const numero = typeof result.numero_mandat === 'string' && result.numero_mandat.trim() ? result.numero_mandat.trim() : null
    return numero ? `Mandat ${numero}` : `Generation mandat ${job.hektor_annonce_id ?? payload.hektor_annonce_id ?? ''}`.trim()
  }
  if (job.job_type === 'create_hektor_contact' || job.job_type === 'update_hektor_contact' || job.job_type === 'delete_hektor_contact' || job.job_type === 'refresh_console_contact_data') {
    const contactName = [payload.first_name, payload.last_name].filter((value) => typeof value === 'string' && value.trim()).join(' ')
    const contactId = String(result.hektor_contact_id ?? payload.hektor_contact_id ?? payload.contact_id ?? '').trim()
    if (contactName.trim()) return `Contact ${contactName.trim()}`
    return contactId ? `Contact ${contactId}` : 'Contact Hektor'
  }
  if (job.job_type === 'create_hektor_mandant_contact' || job.job_type === 'update_hektor_mandant_contact' || job.job_type === 'link_hektor_mandant') {
    const contact = typeof payload.last_name === 'string' && payload.last_name.trim() ? payload.last_name.trim() : null
    return contact ? `Mandant ${contact}` : 'Mandant Hektor'
  }
  if (job.job_type === 'sync_hektor_photos') return `Photos ${job.hektor_annonce_id ?? payload.hektor_annonce_id ?? ''}`.trim()
  const folder = typeof result.folder_number === 'string' ? result.folder_number : null
  const title = typeof payload.title === 'string' && payload.title.trim() ? payload.title.trim() : null
  return folder ? `Creation ${folder}` : title ? `Creation ${title}` : 'Creation annonce Hektor'
}

function hektorActionJobLabel(job: ConsoleJob) {
  const matterportLabel = matterportJobActionLabel(job.job_type)
  if (matterportLabel) return matterportLabel
  if (job.job_type === 'delete_hektor_annonce') return 'Suppression en cours'
  if (job.job_type === 'archive_hektor_annonce') return 'Archivage en cours'
  if (job.job_type === 'restore_hektor_annonce') return 'Desarchivage en cours'
  if (job.job_type === 'change_hektor_annonce_status') return 'Changement statut'
  if (job.job_type === 'delete_document_from_hektor') return 'Suppression document'
  if (job.job_type === 'upload_document_to_hektor') return 'Ajout document'
  if (job.job_type === 'upload_hektor_photo') return 'Ajout photo'
  if (job.job_type === 'prepare_document_cloud') return 'Preparation document'
  if (job.job_type === 'prepare_archived_annonce_detail') return 'Detail archive'
  if (job.job_type === 'prepare_historical_annonce_detail') return 'Detail Vendu/Clos'
  if (job.job_type === 'update_hektor_annonce_fields') return 'Modification en cours'
  if (job.job_type === 'create_hektor_mandat_auto_number') return 'Generation mandat'
  if (job.job_type === 'create_hektor_contact') return 'Creation contact'
  if (job.job_type === 'update_hektor_contact') return 'Modification contact'
  if (job.job_type === 'delete_hektor_contact') return 'Suppression contact'
  if (job.job_type === 'refresh_console_contact_data') return 'Sync contact'
  if (job.job_type === 'create_hektor_mandant_contact' || job.job_type === 'update_hektor_mandant_contact' || job.job_type === 'link_hektor_mandant') return 'Mandant en cours'
  if (job.job_type === 'sync_hektor_photos') return 'Photos en cours'
  return 'Creation en cours'
}

function hektorActionJobTone(job: ConsoleJob) {
  if (job.job_type.startsWith('matterport_')) return job.job_type === 'matterport_archive' ? 'delete' : 'update'
  if (job.job_type === 'archive_hektor_annonce') return 'update'
  if (job.job_type === 'restore_hektor_annonce') return 'update'
  if (job.job_type === 'change_hektor_annonce_status') return 'update'
  if (job.job_type === 'delete_hektor_annonce' || job.job_type === 'delete_hektor_contact' || job.job_type === 'delete_document_from_hektor') return 'delete'
  if (job.job_type === 'update_hektor_annonce_fields') return 'update'
  if (job.job_type === 'create_hektor_mandat_auto_number') return 'contact'
  if (job.job_type === 'create_hektor_contact' || job.job_type === 'update_hektor_contact' || job.job_type === 'refresh_console_contact_data') return 'contact'
  if (job.job_type === 'create_hektor_mandant_contact' || job.job_type === 'update_hektor_mandant_contact' || job.job_type === 'link_hektor_mandant') return 'contact'
  if (job.job_type === 'upload_document_to_hektor' || job.job_type === 'upload_hektor_photo' || job.job_type === 'prepare_document_cloud' || job.job_type === 'prepare_archived_annonce_detail' || job.job_type === 'prepare_historical_annonce_detail' || job.job_type === 'sync_hektor_photos') return 'document'
  return 'create'
}

function hektorActionJobDetail(job: ConsoleJob) {
  const payload = job.payload_json ?? {}
  const result = job.result_json ?? {}
  const agency = typeof payload.agence_nom === 'string' ? payload.agence_nom : null
  const negotiator = typeof payload.hektor_user_label === 'string' ? payload.hektor_user_label : null
  const folder = typeof result.folder_number === 'string' ? result.folder_number : null
  if (job.status === 'error') return job.error_message || 'Action Hektor en erreur'
  if (job.job_type.startsWith('matterport_')) return 'Commande envoyee au worker Matterport local'
  if (job.job_type === 'upload_document_to_hektor') return 'Document envoye au PC serveur'
  if (job.job_type === 'upload_hektor_photo') return 'Photo envoyee au PC serveur'
  if (job.job_type === 'prepare_document_cloud') return 'Mise en cloud demandee'
  if (job.job_type === 'prepare_archived_annonce_detail') return 'Preparation locale demandee'
  if (job.job_type === 'prepare_historical_annonce_detail') return 'Preparation locale demandee'
  if (job.job_type === 'delete_document_from_hektor') return 'Suppression Hektor demandee'
  if (job.job_type === 'archive_hektor_annonce') return 'Archivage Hektor puis resynchronisation'
  if (job.job_type === 'restore_hektor_annonce') return 'Reintegration Hektor puis resynchronisation'
  if (job.job_type === 'change_hektor_annonce_status') return 'Transaction Hektor puis resynchronisation'
  if (job.job_type === 'update_hektor_annonce_fields') return 'Modification puis resynchronisation'
  if (job.job_type === 'create_hektor_mandat_auto_number') return 'Numero reserve puis resynchronisation'
  if (job.job_type === 'create_hektor_contact') return 'Creation puis resynchronisation ciblee'
  if (job.job_type === 'update_hektor_contact') return 'Modification puis resynchronisation ciblee'
  if (job.job_type === 'delete_hektor_contact') return 'Suppression Hektor puis nettoyage app'
  if (job.job_type === 'refresh_console_contact_data') return 'Lecture detail contact puis push Supabase'
  if (job.job_type === 'create_hektor_mandant_contact' || job.job_type === 'link_hektor_mandant') return 'Association puis resynchronisation'
  if (job.job_type === 'update_hektor_mandant_contact') return 'Modification puis resynchronisation'
  if (job.job_type === 'sync_hektor_photos') return 'Index photos Console'
  if (folder) return `${folder} synchronise dans l'app`
  return [negotiator, agency].filter(Boolean).join(' - ') || `Job ${consoleJobShortId(job)}`
}

function isPrimaryHektorActionJob(job: ConsoleJob) {
  return job.job_type !== 'refresh_console_data' && job.job_type !== 'refresh_console_contact_data'
}

function hektorJobSyncJobId(job: ConsoleJob) {
  const syncJob = job.result_json?.sync_job
  if (!syncJob || typeof syncJob !== 'object') return null
  const id = (syncJob as { id?: unknown; job_id?: unknown; sync_job_id?: unknown }).id
    ?? (syncJob as { job_id?: unknown }).job_id
    ?? (syncJob as { sync_job_id?: unknown }).sync_job_id
  return typeof id === 'string' && id.trim() ? id : null
}

function hektorActionRelatedJobIds(jobs: ConsoleJob[]) {
  return Array.from(new Set(jobs.flatMap((job) => [job.id, hektorJobSyncJobId(job)].filter((id): id is string => Boolean(id)))))
}

function hektorCreatedAnnonceId(job: ConsoleJob) {
  const resultId = job.result_json?.hektor_annonce_id
  const payloadId = job.payload_json?.hektor_annonce_id
  const source = resultId ?? job.hektor_annonce_id ?? payloadId
  const value = String(source ?? '').trim()
  return value || null
}

async function loadHektorActionAppDossier(job: ConsoleJob, scope?: DataScope | null): Promise<Dossier | null> {
  const hektorAnnonceId = hektorCreatedAnnonceId(job)
  if (!hektorAnnonceId) return null
  if (job.job_type === 'prepare_archived_annonce_detail') return loadArchivedAnnonceDetailCache(hektorAnnonceId)
  if (job.job_type === 'prepare_historical_annonce_detail') return loadHistoricalAnnonceDetailCache(hektorAnnonceId)
  const currentDossier = await loadDossierByHektorAnnonceId(hektorAnnonceId, scope)
  if (currentDossier) return currentDossier
  const historicalDossier = await loadHistoricalAnnonceDetailCache(hektorAnnonceId)
  if (historicalDossier) return historicalDossier
  return loadArchivedAnnonceDetailCache(hektorAnnonceId)
}

function hektorActionCanFinishWithoutAppDossier(job: ConsoleJob) {
  return [
    'delete_document_from_hektor',
    'prepare_document_cloud',
    'sync_console_documents',
    'sync_hektor_photos',
    'create_hektor_contact',
    'update_hektor_contact',
    'delete_hektor_contact',
    'refresh_console_contact_data',
  ].includes(job.job_type)
}

function hektorActionProgress(job: ConsoleJob, syncJob: ConsoleJob | null, appDossier?: Dossier | null) {
  if (job.status === 'error' || syncJob?.status === 'error') return 'error'
  const syncJobId = hektorJobSyncJobId(job)
  if (job.job_type === 'create_hektor_draft_annonce' && job.status === 'done' && !appDossier) return 'syncing'
  if (syncJobId && syncJob?.status !== 'done') {
    if (job.status === 'done') return 'syncing'
    if (job.status === 'running') return 'creating'
    return 'queued'
  }
  if (syncJobId && syncJob?.status === 'done') return 'available'
  if (appDossier) return 'available'
  if (job.job_type !== 'create_hektor_draft_annonce' && job.status === 'done') return hektorActionCanFinishWithoutAppDossier(job) ? 'available' : 'syncing'
  if (job.status === 'done') return 'syncing'
  if (job.status === 'running') return 'creating'
  return 'queued'
}

function hektorActionProgressLabel(progress: ReturnType<typeof hektorActionProgress>, job?: ConsoleJob) {
  if (progress === 'available') {
    if (!job || job.job_type === 'create_hektor_draft_annonce') return 'Annonce disponible'
    if (job.job_type === 'update_hektor_annonce_fields') return 'Modification terminee'
    if (job.job_type === 'create_hektor_mandat_auto_number') return 'Mandat genere'
    if (job.job_type === 'create_hektor_contact') return 'Contact cree'
    if (job.job_type === 'update_hektor_contact') return 'Contact modifie'
    if (job.job_type === 'delete_hektor_contact') return 'Contact supprime'
    if (job.job_type === 'refresh_console_contact_data') return 'Contact synchronise'
    if (job.job_type === 'create_hektor_mandant_contact' || job.job_type === 'link_hektor_mandant') return 'Mandant synchronise'
    if (job.job_type === 'update_hektor_mandant_contact') return 'Mandant modifie'
    if (job.job_type === 'upload_document_to_hektor') return 'Document ajoute'
    if (job.job_type === 'upload_hektor_photo') return 'Photo ajoutee'
    if (job.job_type === 'prepare_document_cloud') return 'Document pret'
    if (job.job_type === 'prepare_archived_annonce_detail') return 'Archive prete'
    if (job.job_type === 'prepare_historical_annonce_detail') return 'Fiche prete'
    if (job.job_type === 'delete_document_from_hektor') return 'Document supprime'
    if (job.job_type === 'sync_hektor_photos') return 'Photos synchronisees'
    if (job.job_type === 'delete_hektor_annonce') return 'Suppression terminee'
    if (job.job_type === 'archive_hektor_annonce') return 'Annonce archivee'
    if (job.job_type === 'restore_hektor_annonce') return 'Annonce desarchivee'
    if (job.job_type === 'change_hektor_annonce_status') return 'Statut mis a jour'
    return 'Action terminee'
  }
  if (progress === 'syncing') {
    if (!job || job.job_type === 'create_hektor_draft_annonce') return "Ajout dans l'app"
    if (job.job_type === 'create_hektor_contact' || job.job_type === 'update_hektor_contact' || job.job_type === 'delete_hektor_contact' || job.job_type === 'refresh_console_contact_data') return 'Synchronisation contact'
    if (job.job_type === 'update_hektor_annonce_fields' || job.job_type === 'update_hektor_mandant_contact' || job.job_type === 'archive_hektor_annonce' || job.job_type === 'restore_hektor_annonce' || job.job_type === 'change_hektor_annonce_status') return "Mise a jour de l'app"
    if (job.job_type === 'create_hektor_mandat_auto_number') return 'Synchronisation mandat'
    if (job.job_type === 'create_hektor_mandant_contact' || job.job_type === 'link_hektor_mandant') return 'Synchronisation mandant'
    if (job.job_type === 'upload_document_to_hektor' || job.job_type === 'prepare_document_cloud' || job.job_type === 'prepare_archived_annonce_detail' || job.job_type === 'prepare_historical_annonce_detail' || job.job_type === 'delete_document_from_hektor') return 'Synchronisation document'
    if (job.job_type === 'upload_hektor_photo') return 'Mise a jour galerie'
    if (job.job_type === 'sync_hektor_photos') return 'Synchronisation photos'
    return "Mise a jour de l'app"
  }
  if (progress === 'creating') return job && job.job_type !== 'create_hektor_draft_annonce' ? 'Commande Hektor' : 'Creation Hektor'
  if (progress === 'error') return 'Action a verifier'
  return 'En attente'
}

function hektorActionWaitingLabel(job: ConsoleJob) {
  if (job.job_type === 'delete_hektor_contact') return 'Hektor a supprime le contact. Nettoyage app en cours...'
  if (job.job_type === 'create_hektor_contact' || job.job_type === 'update_hektor_contact' || job.job_type === 'refresh_console_contact_data') return 'Hektor a mis a jour le contact. Synchronisation app en cours...'
  if (job.job_type === 'update_hektor_mandant_contact') return 'Hektor a modifie le mandant. Mise a jour de l app en cours...'
  if (job.job_type === 'update_hektor_annonce_fields') return 'Hektor a modifie l annonce. Mise a jour de l app en cours...'
  if (job.job_type === 'archive_hektor_annonce') return 'Hektor a archive l annonce. Mise a jour de l app en cours...'
  if (job.job_type === 'restore_hektor_annonce') return 'Hektor a desarchive l annonce. Mise a jour de l app en cours...'
  if (job.job_type === 'change_hektor_annonce_status') return 'Hektor a accepte le statut. Reprise des informations transaction en cours...'
  if (job.job_type === 'create_hektor_mandat_auto_number') return 'Hektor a genere le numero de mandat. Mise a jour de l app en cours...'
  if (job.job_type === 'create_hektor_mandant_contact' || job.job_type === 'link_hektor_mandant') return 'Hektor a mis a jour le mandant. Synchronisation app en cours...'
  if (job.job_type === 'create_hektor_draft_annonce') return 'Annonce creee dans Hektor. Ajout dans l app en cours...'
  if (job.job_type === 'upload_document_to_hektor') return 'Document ajoute dans Hektor. Synchronisation app en cours...'
  if (job.job_type === 'upload_hektor_photo') return 'Photo ajoutee dans Hektor. Mise a jour de la galerie en cours...'
  if (job.job_type === 'delete_document_from_hektor') return 'Document supprime dans Hektor. Mise a jour app en cours...'
  if (job.job_type === 'sync_hektor_photos') return 'Photos Hektor lues. Mise a jour de la galerie app en cours...'
  return 'Commande Hektor terminee. Mise a jour de l app en cours...'
}

function HektorActionStatusPopup(props: {
  jobs: ConsoleJob[]
  linkedDossiers: Record<string, Dossier>
  onDismiss: (jobId: string) => void
  onOpenAppDossier: (job: ConsoleJob) => void
}) {
  const [openButtonReadyJobId, setOpenButtonReadyJobId] = useState<string | null>(null)
  const primaryJobs = props.jobs.filter(isPrimaryHektorActionJob).slice(0, 3)
  const jobsById = new Map(props.jobs.map((job) => [job.id, job]))
  const mainJob = primaryJobs[0] ?? null
  const mainSyncJobId = mainJob ? hektorJobSyncJobId(mainJob) : null
  const mainSyncJob = mainSyncJobId ? jobsById.get(mainSyncJobId) ?? null : null
  const mainAnnonceId = mainJob ? hektorCreatedAnnonceId(mainJob) : null
  const mainDossier = mainAnnonceId ? props.linkedDossiers[mainAnnonceId] : null
  const mainProgress = mainJob ? hektorActionProgress(mainJob, mainSyncJob, mainDossier) : 'queued'
  const isAvailable = mainProgress === 'available'
  const isError = mainProgress === 'error'
  const isWaitingForAppSync = Boolean(mainJob && mainProgress === 'syncing' && mainJob.status === 'done')
  const appOpenReady = Boolean(mainJob && isAvailable && mainJob.job_type !== 'delete_hektor_annonce' && mainDossier)
  const canShowOpenDelay = Boolean(appOpenReady && openButtonReadyJobId !== mainJob?.id)
  const canOpenApp = Boolean(appOpenReady && openButtonReadyJobId === mainJob?.id)
  const canOpenHektor = Boolean(mainJob && mainAnnonceId && mainJob.job_type !== 'delete_hektor_annonce')

  useEffect(() => {
    setOpenButtonReadyJobId(null)
    if (!mainJob || !appOpenReady) return
    const timer = window.setTimeout(() => setOpenButtonReadyJobId(mainJob.id), 1200)
    return () => window.clearTimeout(timer)
  }, [appOpenReady, mainJob?.id])

  if (!mainJob) return null

  return (
    <aside className={`hektor-action-popup hektor-action-popup-${mainProgress}`} aria-live="polite">
      <div className="hektor-action-popup-head">
        <span className="hektor-action-popup-icon" aria-hidden="true">{isError ? '!' : isAvailable ? 'OK' : 'H'}</span>
        <div>
          <p className="hektor-action-popup-eyebrow">Suivi Hektor</p>
          <h3>{hektorActionProgressLabel(mainProgress, mainJob)}</h3>
        </div>
        <button className="hektor-action-popup-close" type="button" onClick={() => props.onDismiss(mainJob.id)} aria-label="Masquer le suivi">x</button>
      </div>

      <div className="hektor-action-popup-main">
        <strong>{hektorActionJobTitle(mainJob)}</strong>
        <span>{isWaitingForAppSync ? hektorActionWaitingLabel(mainJob) : canShowOpenDelay ? "Tout est synchronise. Patientez, preparation de l'ouverture..." : hektorActionJobDetail(mainJob)}</span>
      </div>

      <div className="hektor-action-steps">
        <span className={mainJob.status === 'done' ? 'is-done' : mainJob.status === 'running' ? 'is-current' : isError ? 'is-error' : ''}>
          <i aria-hidden="true" /> Hektor
        </span>
        <span className={isAvailable ? 'is-done' : mainProgress === 'syncing' ? 'is-current' : mainSyncJob?.status === 'error' ? 'is-error' : ''}>
          <i aria-hidden="true" /> App
        </span>
      </div>

      <div className="hektor-action-popup-actions">
        {canOpenApp ? (
          <button className="ghost-button button-primary" type="button" onClick={() => props.onOpenAppDossier(mainJob)}>Ouvrir le detail</button>
        ) : null}
        {isWaitingForAppSync ? (
          <button className="ghost-button button-primary is-waiting" type="button" disabled>Actualisation app...</button>
        ) : null}
        {canShowOpenDelay ? (
          <button className="ghost-button button-primary is-waiting hektor-action-wait-button" type="button" disabled>
            <span className="hektor-action-wait-spinner" aria-hidden="true" />
            Patientez...
          </button>
        ) : null}
        {canOpenHektor && mainAnnonceId ? <button className="ghost-button" type="button" onClick={() => openHektorAnnonce(mainAnnonceId)}>Hektor</button> : null}
      </div>

      {primaryJobs.length > 1 ? (
        <div className="hektor-action-popup-queue">
          {primaryJobs.slice(1).map((job) => (
            <button key={job.id} type="button" onClick={() => props.onDismiss(job.id)}>
              <span>{hektorActionJobLabel(job)}</span>
              <strong>{hektorActionJobTitle(job)}</strong>
            </button>
          ))}
        </div>
      ) : null}
    </aside>
  )
}

function userInitials(displayName?: string | null, email?: string | null) {
  const source = (displayName ?? '').trim() || (email ?? '').split('@')[0] || 'U'
  const parts = source.split(/[\s._-]+/).filter(Boolean)
  return parts.slice(0, 2).map((part) => part[0]?.toUpperCase() ?? '').join('') || 'U'
}

function normalizeEmail(value?: string | null) {
  return (value ?? '').trim().toLowerCase()
}

function profileRoleLabel(role?: UserProfile['role'] | null) {
  if (role === 'admin') return 'Administrateur'
  if (role === 'manager') return 'Manager'
  if (role === 'commercial') return 'Negociateur'
  if (role === 'lecture') return 'Lecture'
  return 'Profil'
}

