  function updateHektorActionJobs(updater: (current: ConsoleJob[]) => ConsoleJob[]) {
    setHektorActionJobs((current) => {
      const next = updater(current)
      hektorActionJobsRef.current = next
      return next
    })
  }

  function rememberHektorActionJob(job: ConsoleJob) {
    updateHektorActionJobs((current) => {
      const withoutSame = current.filter((item) => item.id !== job.id)
      return [job, ...withoutSame].slice(0, 12)
    })
    setDismissedHektorActionJobIds((current) => current.filter((id) => id !== job.id))
  }

  function handleOptimisticContactDeleted(contact: AppContact) {
    const contactId = contact.hektor_contact_id
    const isArchived = contactBool(contact.archive)
    const highRisk = contact.duplicate_max_severity === 'high' || contact.duplicate_max_severity === 'critical'
    setContactsDirectory((current) => current.filter((item) => item.hektor_contact_id !== contactId))
    setContactsTotal((current) => Math.max(0, current - 1))
    setContactStats((current) => ({
      ...current,
      total: Math.max(0, current.total - 1),
      active: isArchived ? current.active : Math.max(0, current.active - 1),
      archived: isArchived ? Math.max(0, current.archived - 1) : current.archived,
      duplicates: contact.duplicate_group_count ? Math.max(0, current.duplicates - 1) : current.duplicates,
      highRiskDuplicates: highRisk ? Math.max(0, current.highRiskDuplicates - 1) : current.highRiskDuplicates,
      linked: (contact.linked_annonce_count ?? 0) > 0 ? Math.max(0, current.linked - 1) : current.linked,
      searchContacts: (contact.total_search_count ?? 0) > 0 ? Math.max(0, current.searchContacts - 1) : current.searchContacts,
      activeSearchContacts: (contact.active_search_count ?? 0) > 0 ? Math.max(0, current.activeSearchContacts - 1) : current.activeSearchContacts,
      eligible: contactBool(contact.supabase_sync_eligible) ? Math.max(0, current.eligible - 1) : current.eligible,
    }))
    setSelectedContactId((current) => current === contactId ? null : current)
    setSelectedContactRelations([])
    setSelectedContactSearches([])
    setNoticeMessage(`Suppression demandee pour ${contact.display_name || `contact ${contactId}`}.`)
  }

  const sessionEmail = normalizeEmail(session?.user.email ?? profile?.email ?? null)
  const dataScope = useMemo<DataScope | undefined>(() => {
    if (profile?.role !== 'commercial') return undefined
    return { negotiatorEmail: sessionEmail || null }
  }, [profile?.role, sessionEmail])
  const draftNegotiatorOptions = useMemo(() => {
    const selectedAgency = draftAnnonceAgency.trim()
    return hektorNegotiators.filter((item) => {
      if (profile?.role === 'commercial') {
        return normalizeEmail(item.email) === sessionEmail && (!selectedAgency || !item.agenceNom || item.agenceNom === selectedAgency)
      }
      if (!selectedAgency) return true
      return !item.agenceNom || item.agenceNom === selectedAgency
    })
  }, [draftAnnonceAgency, hektorNegotiators, profile?.role, sessionEmail])
  const selectedDraftNegotiator = useMemo(() => {
    return draftNegotiatorOptions.find((item) => item.idUser === draftAnnonceNegotiatorId) ?? null
  }, [draftAnnonceNegotiatorId, draftNegotiatorOptions])
  const selectedDraftExistingMandant = useMemo(() => {
    return draftExistingMandantOptions.find((item) => item.hektor_contact_id === draftExistingMandantId) ?? null
  }, [draftExistingMandantId, draftExistingMandantOptions])
  const draftAnnonceSelectedTypeGroup = draftAnnoncePropertyGroupForTypeId(draftAnnonceTypeId)
  const draftAnnonceSelectedTypeOptions = draftAnnonceTypeOptionsForGroup(draftAnnonceSelectedTypeGroup.id)
  const draftAnnonceTypeRules = draftAnnonceTypeProfile(draftAnnonceTypeId)
  const draftAnnonceStepIndex = Math.max(0, draftAnnonceStepOrder.indexOf(draftAnnonceStep))
  const draftAnnonceStepProgress = ((draftAnnonceStepIndex + 1) / draftAnnonceStepOrder.length) * 100
  const draftAnnonceCurrentStep = draftAnnonceStepMeta[draftAnnonceStep]
  const draftAnnonceReviewSurface = draftAnnonceTypeRules.surfaceMode === 'terrain'
    ? draftAnnonceAdvanced.landSurface
    : draftAnnonceTypeRules.surfaceMode === 'garage'
      ? draftAnnonceAdvanced.garageSurface
      : draftAnnonceSurface
  const draftAnnonceVisibleWizardGroups = filterDraftAnnonceWizardGroupsForProfile(draftAnnonceWizardGroups, draftAnnonceTypeRules.kind)
  const draftAnnonceVisibleWizardFieldNames = new Set(draftAnnonceVisibleWizardGroups.flatMap((section) => section.fields.map((field) => field.name)))
  const draftAnnonceCoreFilledCount = [
    draftAnnonceTitle,
    draftAnnonceAgency,
    selectedDraftNegotiator?.label ?? '',
    draftAnnonceAddress,
    draftAnnoncePostalCode,
    draftAnnonceCity,
    draftAnnoncePrice,
    draftAnnonceReviewSurface,
    draftAnnonceTypeRules.showRooms ? draftAnnonceRoomCount : '',
    draftAnnonceTypeRules.showBedrooms ? draftAnnonceBedroomCount : '',
    draftAnnonceTypeRules.showLevels ? draftAnnonceLevelCount : '',
  ].filter((value) => value.trim()).length
  const draftAnnonceAdvancedFilledCount = Object.entries(draftAnnonceAdvanced)
    .filter(([key, value]) => isDraftAnnonceAdvancedFieldVisibleForProfile(draftAnnonceTypeRules.kind, key as DraftAnnonceAdvancedKey) && value.trim())
    .length
  const draftAnnonceWizardFilledCount = Object.entries(draftAnnonceWizardFields)
    .filter(([key, value]) => draftAnnonceVisibleWizardFieldNames.has(key) && value.trim())
    .length
  const draftAnnonceCompositionFilledCount = draftAnnonceCompositionPieces.filter((piece) => hektorCompositionPieceHasContent(piece)).length
  const draftAnnonceOfferGroups = draftAnnonceVisibleWizardGroups.filter((section) => section.step === 1)
  const draftAnnonceSecteurGroups = draftAnnonceVisibleWizardGroups.filter((section) => section.step === 3)
  const draftAnnonceDetailGroups = draftAnnonceVisibleWizardGroups.filter((section) => section.step === 5)
  const draftAnnonceMandatGroups = draftAnnonceVisibleWizardGroups.filter((section) => section.step === 6)
  const draftAnnonceDiffusionGroups = draftAnnonceVisibleWizardGroups.filter((section) => section.step === 7)
  const draftAnnonceHasNewMandantDraft = [draftMandantCivility, draftMandantLastName, draftMandantFirstName, draftMandantEmail, draftMandantPhone, draftMandantAddress, draftMandantPostalCode, draftMandantCity].some((value) => value.trim())
  const draftAnnonceHasExistingMandantDraft = draftMandantChoice === 'existing' && /^\d+$/.test(draftExistingMandantId.trim())
  const draftAnnonceMandantReviewLabel = draftAnnonceHasExistingMandantDraft
    ? mandantContactOptionTitle(selectedDraftExistingMandant) || `Contact ${draftExistingMandantId}`
    : draftMandantChoice === 'new' && draftAnnonceHasNewMandantDraft
      ? [draftMandantLastName, draftMandantFirstName].filter((value) => value.trim()).join(' ') || draftMandantEmail || 'A completer'
      : draftMandantChoice === 'new'
        ? 'Nouveau mandant a completer'
        : draftMandantChoice === 'existing'
          ? 'Contact a selectionner'
          : 'Non ajoute'
  const draftAnnonceCreationStatus = screen === 'estimations' ? 'estimation' : 'active'
  const draftAnnonceCreationStatusLabel = draftAnnonceCreationStatus === 'estimation' ? 'Estimation' : 'Actif'
  const negotiatorAssignAgency = useMemo(() => {
    return hektorAgencies.find((item) => item.idAgence === negotiatorAssignAgencyValue) ?? null
  }, [hektorAgencies, negotiatorAssignAgencyValue])
  const negotiatorAssignOptions = useMemo(() => {
    if (!negotiatorAssignAgencyValue) return []
    return hektorNegotiators
      .filter((item) => item.hektorAgenceId === negotiatorAssignAgencyValue)
      .slice()
      .sort((left, right) => left.label.localeCompare(right.label, 'fr'))
  }, [hektorNegotiators, negotiatorAssignAgencyValue])
  useEffect(() => {
    setSearchDraft(filters.query)
  }, [filters.query])
  useEffect(() => {
    const trimmed = searchDraft.trim()
    const nextQuery = trimmed.length === 0 ? '' : trimmed.length >= 3 ? searchDraft : ''
    if (nextQuery === filters.query) return
    const timeoutId = window.setTimeout(() => {
      updateFilter('query', nextQuery)
    }, 400)
    return () => window.clearTimeout(timeoutId)
  }, [filters.query, searchDraft])
  const dataFilters = useMemo<AppFilters>(() => {
    if (screen === 'suivi') {
      return {
        ...filters,
        archive: filters.archive === allFilterValue ? activeArchiveFilterValue : filters.archive,
        statut: filters.statut === allFilterValue ? activeListingsFilterValue : filters.statut,
      }
    }
    if (screen === 'estimations') {
      return {
        ...filters,
        archive: filters.archive === allFilterValue ? activeArchiveFilterValue : filters.archive,
        statut: 'Estimation',
      }
    }
    return applyAnnonceSearchDefaultScope(screen, filters, annonceSearchScope)
  }, [annonceSearchScope, filters, screen])
  const listingStatusOptions = useMemo(
    () => mergeFilterOptions([
      activeListingsFilterOption,
      ...filterCatalog.statuts,
      ...historicalListingStatusOptions,
    ]),
    [filterCatalog.statuts],
  )
  const activeHektorActionJobs = useMemo(() => hektorActionJobs.filter((job) => isPrimaryHektorActionJob(job) && isConsoleJobActive(job)), [hektorActionJobs])
  const visibleHektorActionPopupJobs = useMemo(() => {
    const dismissed = new Set(dismissedHektorActionJobIds)
    return hektorActionJobs
      .filter((job) => !dismissed.has(job.id))
      .filter((job) => isConsoleJobActive(job) || job.status === 'done' || job.status === 'error')
      .sort((left, right) => new Date(right.requested_at).getTime() - new Date(left.requested_at).getTime())
      .slice(0, 8)
  }, [dismissedHektorActionJobIds, hektorActionJobs])
  const activeDeleteAnnonceJobs = useMemo(() => activeHektorActionJobs.filter((job) => job.job_type === 'delete_hektor_annonce'), [activeHektorActionJobs])
  const activeAdminAnnonceJobIds = useMemo(() => new Set(activeHektorActionJobs
    .filter((job) => job.job_type === 'delete_hektor_annonce' || job.job_type === 'archive_hektor_annonce' || job.job_type === 'restore_hektor_annonce' || job.job_type === 'change_hektor_annonce_status')
    .map((job) => String(job.hektor_annonce_id ?? job.payload_json?.hektor_annonce_id ?? ''))
    .filter(Boolean)), [activeHektorActionJobs])
  const preparingArchiveDetailIds = useMemo(() => new Set(activeHektorActionJobs
    .filter((job) => job.job_type === 'prepare_archived_annonce_detail' || job.job_type === 'prepare_historical_annonce_detail')
    .map((job) => String(job.hektor_annonce_id ?? job.payload_json?.hektor_annonce_id ?? ''))
    .filter(Boolean)), [activeHektorActionJobs])
  const lightweightDetailJob = useMemo(() => {
    if (!lightweightDetailTarget) return null
    const targetId = String(lightweightDetailTarget.hektor_annonce_id)
    return hektorActionJobs.find((job) =>
      (job.job_type === 'prepare_archived_annonce_detail' || job.job_type === 'prepare_historical_annonce_detail') &&
      String(job.hektor_annonce_id ?? job.payload_json?.hektor_annonce_id ?? '') === targetId,
    ) ?? null
  }, [hektorActionJobs, lightweightDetailTarget])
  const deletingAppDossierIds = useMemo(() => new Set(activeDeleteAnnonceJobs.map((job) => Number(job.app_dossier_id)).filter((value) => Number.isFinite(value))), [activeDeleteAnnonceJobs])
  const deletingHektorAnnonceIds = useMemo(() => new Set(activeDeleteAnnonceJobs.map((job) => String(job.hektor_annonce_id ?? job.payload_json?.hektor_annonce_id ?? '')).filter(Boolean)), [activeDeleteAnnonceJobs])
  const visibleDossiers = useMemo(() => dossiers.filter((item) => !deletingAppDossierIds.has(item.app_dossier_id) && !deletingHektorAnnonceIds.has(String(item.hektor_annonce_id))), [dossiers, deletingAppDossierIds, deletingHektorAnnonceIds])

  useEffect(() => {
    sessionRef.current = session
  }, [session])

  useEffect(() => {
    if (!hasSupabaseEnv) {
      void bootstrapApp()
      return
    }

    if (typeof window !== 'undefined') {
      const hash = window.location.hash || ''
      if (hash.includes('type=recovery')) {
        setRecoveryMode(true)
      }
    }

    void getCurrentSession().then((nextSession) => {
      const sameIdentity = sameSessionIdentity(sessionRef.current, nextSession)
      if (!sameIdentity) {
        sessionRef.current = nextSession
        setSession(nextSession)
      }
      if (nextSession) {
        void bootstrapApp()
      } else {
        setBootLoading(false)
      }
    })

    if (!supabase) return
    const { data } = supabase.auth.onAuthStateChange((event, nextSession) => {
      if (event === 'PASSWORD_RECOVERY') {
        setRecoveryMode(true)
      }
      const sameIdentity = sameSessionIdentity(sessionRef.current, nextSession)
      if (!sameIdentity) {
        sessionRef.current = nextSession
        setSession(nextSession)
      }
      if (nextSession) {
        if (!sameIdentity) void bootstrapApp()
      } else {
        setBootLoading(false)
      }
    })

    return () => data.subscription.unsubscribe()
  }, [dataScope])

  async function bootstrapApp() {
    setBootLoading(true)
    setErrorMessage(null)
    try {
      setCatalogLoading(true)
    } catch (error) {
      setErrorMessage(error instanceof Error ? error.message : 'Erreur de chargement')
    } finally {
      setBootLoading(false)
    }

    Promise.all([loadFilterCatalog(dataScope), loadMandatFilterCatalog(dataScope).catch(() => null)])
      .then(([catalog, mandatCatalog]) => setFilterCatalog(mandatCatalog ? mergeCatalog(catalog, { ...emptyFilterCatalog, ...mandatCatalog }) : catalog))
      .catch(() => setFilterCatalog(emptyFilterCatalog))
      .finally(() => setCatalogLoading(false))
  }

  useEffect(() => {
    if (hasSupabaseEnv && !session) return
    let cancelled = false
    Promise.all([
      session?.user?.id ? loadUserProfile(session.user.id) : Promise.resolve(mockLocalProfile()),
      session?.user?.id ? loadGoogleWorkspaceIdentity(session.user.id) : Promise.resolve(null),
      loadUserNegotiatorContext(session?.user?.email ?? null).catch(() => null),
      loadDiffusionRequests().catch(() => []),
      loadDiffusionRequestEvents().catch(() => []),
    ])
      .then(([nextProfile, nextGoogleWorkspaceIdentity, nextUserNegotiatorContext, rows, events]) => {
        if (cancelled) return
        const profileEmail = normalizeEmail(nextProfile?.email ?? session?.user?.email ?? null)
        const authEmail = normalizeEmail(session?.user?.email ?? null)
        const identityEmail = normalizeEmail(nextGoogleWorkspaceIdentity?.google_email ?? null)
        const identityStatus = nextGoogleWorkspaceIdentity?.link_status ?? null
        const identityOk = Boolean(
          nextGoogleWorkspaceIdentity?.is_active
          && identityStatus === 'linked'
          && identityEmail
          && identityEmail === authEmail,
        )
        if (hasSupabaseEnv && session && (!nextProfile?.is_active || !isGoogleWorkspaceEmail(profileEmail) || !identityOk)) {
          setProfile(null)
          setGoogleWorkspaceIdentity(null)
          setUserNegotiatorContext(null)
          setDiffusionRequests([])
          setDiffusionRequestEvents([])
          setErrorMessage(
            !isGoogleWorkspaceEmail(profileEmail)
              ? `Connexion refusee : utilise une adresse @${googleWorkspaceDomain}.`
              : !nextProfile?.is_active
                ? 'Connexion refusee : profil utilisateur inactif ou non cree dans l application.'
                : identityStatus && identityStatus !== 'linked'
                  ? 'Connexion refusee : liaison Google Workspace a controler par un admin.'
                  : identityEmail && identityEmail !== authEmail
                    ? 'Connexion refusee : compte Google different du profil autorise.'
                    : 'Connexion refusee : liaison Google Workspace absente ou inactive.',
          )
          void signOut()
          return
        }
        setProfile(nextProfile)
        setGoogleWorkspaceIdentity(nextGoogleWorkspaceIdentity)
        setUserNegotiatorContext(nextUserNegotiatorContext)
        setDiffusionRequests(rows)
        setDiffusionRequestEvents(events)
      })
      .catch((error) => {
        if (!cancelled) setErrorMessage(error instanceof Error ? error.message : 'Erreur de chargement profil')
      })
    return () => {
      cancelled = true
    }
  }, [session])

  useEffect(() => {
    if (hasSupabaseEnv && !session) return
    let cancelled = false
    Promise.all([loadHektorNegotiatorOptions(dataScope), loadHektorAgencyOptions()])
      .then(([negotiators, agencies]) => {
        if (!cancelled) {
          setHektorNegotiators(negotiators)
          setHektorAgencies(agencies)
        }
      })
      .catch(() => {
        if (!cancelled) {
          setHektorNegotiators([])
          setHektorAgencies([])
        }
      })
    return () => {
      cancelled = true
    }
  }, [session, dataScope])

  useEffect(() => {
    if (!draftAnnonceModalOpen) return
    if (profile?.role === 'commercial') {
      const ownNegotiator = draftNegotiatorOptions.find((item) => normalizeEmail(item.email) === sessionEmail)
      setDraftAnnonceNegotiatorId(ownNegotiator?.idUser ?? '')
      return
    }
    if (draftAnnonceNegotiatorId && !draftNegotiatorOptions.some((item) => item.idUser === draftAnnonceNegotiatorId)) {
      setDraftAnnonceNegotiatorId('')
    }
  }, [draftAnnonceModalOpen, draftAnnonceNegotiatorId, draftNegotiatorOptions, hektorNegotiators, profile?.role, sessionEmail])

  useEffect(() => {
    if (!draftAnnonceModalOpen || draftAnnonceStep !== 'mandatPrix' || draftMandantChoice !== 'existing') {
      setDraftExistingMandantLoading(false)
      return
    }
    if (!selectedDraftNegotiator?.email) {
      setDraftExistingMandantOptions([])
      setDraftExistingMandantError('Choisis le negociateur Hektor avant de rechercher un mandant.')
      return
    }

    let cancelled = false
    setDraftExistingMandantLoading(true)
    setDraftExistingMandantError(null)
    const timer = window.setTimeout(() => {
      searchMandantContactOptions({
        search: draftExistingMandantSearch,
        scope: { negotiatorEmail: selectedDraftNegotiator.email },
        limit: 12,
      })
        .then((rows) => {
          if (cancelled) return
          setDraftExistingMandantOptions(rows)
          if (draftExistingMandantId && !rows.some((row) => row.hektor_contact_id === draftExistingMandantId)) {
            setDraftExistingMandantId('')
          }
        })
        .catch((error) => {
          if (cancelled) return
          setDraftExistingMandantOptions([])
          setDraftExistingMandantError(error instanceof Error ? error.message : 'Recherche mandant impossible.')
        })
        .finally(() => {
          if (!cancelled) setDraftExistingMandantLoading(false)
        })
    }, draftExistingMandantSearch.trim() ? 220 : 0)

    return () => {
      cancelled = true
      window.clearTimeout(timer)
    }
  }, [draftAnnonceModalOpen, draftAnnonceStep, draftExistingMandantId, draftExistingMandantSearch, draftMandantChoice, selectedDraftNegotiator?.email])

  useEffect(() => {
    if (!negotiatorAssignTarget || !negotiatorAssignValue) return
    if (!negotiatorAssignOptions.some((item) => item.hektorNegociateurId === negotiatorAssignValue)) {
      setNegotiatorAssignValue('')
    }
  }, [negotiatorAssignOptions, negotiatorAssignTarget, negotiatorAssignValue])

