  async function handleSignIn(event: FormEvent<HTMLFormElement>) {
    event.preventDefault()
    setAuthPending(true)
    setErrorMessage(null)
    if (!isGoogleWorkspaceEmail(authEmail)) {
      setErrorMessage(`Connexion refusee : utilise une adresse @${googleWorkspaceDomain}.`)
      setAuthPending(false)
      return
    }
    try {
      await signInWithPassword(authEmail, authPassword)
    } catch (error) {
      setErrorMessage(error instanceof Error ? error.message : 'Connexion impossible')
    } finally {
      setAuthPending(false)
    }
  }

  async function handleGoogleWorkspaceSignIn() {
    setGoogleAuthPending(true)
    setErrorMessage(null)
    try {
      await signInWithGoogleWorkspace(typeof window !== 'undefined' ? window.location.origin : undefined)
    } catch (error) {
      setErrorMessage(error instanceof Error ? error.message : 'Connexion Google impossible')
      setGoogleAuthPending(false)
    }
  }

  async function handleSignOut() {
    try {
      await signOut()
      setDossiers([])
      setMandats([])
      setMandatBroadcasts([])
      setDiffusionRequests([])
      setDiffusionRequestEvents([])
      setWorkItems([])
      setSelectedDossierId(null)
      setSelectedDossier(null)
      setSelectedMandatId(null)
      setProfile(null)
      setGoogleWorkspaceIdentity(null)
    } catch (error) {
      setErrorMessage(error instanceof Error ? error.message : 'Deconnexion impossible')
    }
  }

  function updateFilter<K extends keyof AppFilters>(key: K, value: AppFilters[K]) {
    if (screen === 'mandats') setActiveMandatKpiAction(null)
    if (key !== 'query') setAnnonceSearchScope('current')
    if (screen === 'contacts') setContactDirectLookupId(null)
    setFilters((current) => {
      const next = { ...current, [key]: value }
      const lightweightContext = screen === 'mandats' && usesLightweightAnnonceIndex(next)
      if (lightweightContext && heavyListingFilterKeys.has(key)) {
        next[key] = allFilterValue as AppFilters[K]
      }
      if (key === 'affaire') {
        if (value !== 'offre_achat') next.offreStatus = allFilterValue
        if (value !== 'compromis') next.compromisStatus = allFilterValue
      }
      if (key === 'archive' && value === archivedFilterValue) {
        clearHeavyListingFilters(next)
      }
      if (key === 'statut' && isHistoricalListingStatus(value) && next.archive !== archivedFilterValue) {
        next.archive = allFilterValue
        clearHeavyListingFilters(next)
      }
      return next
    })
    setDossierPage(1)
    setMandatPage(1)
    setWorkItemPage(1)
    setContactPage(1)
  }

  function resetFilters() {
    setAnnonceSearchScope('current')
    setContactDirectLookupId(null)
    setFilters(defaultFiltersForScreen(screen))
    setMandatDrilldownLabel(null)
    setActiveMandatKpiAction(null)
    setSuiviDrilldownLabel(null)
    setSuiviRequestFilter(screen === 'suivi' ? 'pending_or_in_progress' : null)
    setPriorityPanelOpen(false)
    setCommercialMetricsExpanded(false)
    setDossierPage(1)
    setMandatPage(1)
    setWorkItemPage(1)
    setContactPage(1)
    setDetailOpen(false)
  }

