const googleAgendaDurationOptions = ['30', '45', '60', '90', '120']

function splitEmailList(value: string) {
  return value
    .split(/[;,\s]+/g)
    .map((item) => item.trim().toLowerCase())
    .filter((item, index, list) => item && item.includes('@') && list.indexOf(item) === index)
}

function joinEmailList(values: string[]) {
  return values
    .map((item) => item.trim().toLowerCase())
    .filter((item, index, list) => item && item.includes('@') && list.indexOf(item) === index)
    .join(', ')
}

function detailContactAgendaEmail(contact: DetailContact) {
  return safeText(contact.email).toLowerCase()
}

function detailContactAgendaLabel(contact: DetailContact) {
  return contactPersonDisplayName(contact) || contact.name || contact.email || contact.phone || 'Contact'
}

function contactOptionAgendaEmail(contact: MandantContactSearchOption) {
  return safeText(contact.email).toLowerCase()
}

function hektorContactInputAgendaEmail(contact: HektorContactIdentityInput) {
  return safeText(contact.email).toLowerCase()
}

type GoogleAgendaInviteeContactLink = {
  email: string
  label?: string | null
  hektorContactId?: string | null
  source?: string | null
}

type GoogleAgendaLinkedInviteeOption = {
  key: string
  label: string
  email: string
  meta: string
  hektorContactId?: string | null
  link: GoogleAgendaInviteeContactLink | null
}

function normalizeGoogleAgendaInviteeContactLink(value: unknown): GoogleAgendaInviteeContactLink | null {
  if (!value || typeof value !== 'object') return null
  const record = value as Record<string, unknown>
  const email = safeText(record.email).toLowerCase()
  if (!email || !email.includes('@')) return null
  return {
    email,
    label: safeText(record.label) || null,
    hektorContactId: safeText(record.hektor_contact_id) || safeText(record.hektorContactId) || null,
    source: safeText(record.source) || null,
  }
}

function mergeGoogleAgendaInviteeContactLinks(
  current: GoogleAgendaInviteeContactLink[],
  next: GoogleAgendaInviteeContactLink[],
  emailScope?: string[],
) {
  const allowed = emailScope ? new Set(emailScope.map((email) => email.trim().toLowerCase()).filter(Boolean)) : null
  const links = new Map<string, GoogleAgendaInviteeContactLink>()
  const addLink = (link: GoogleAgendaInviteeContactLink) => {
    const normalized = normalizeGoogleAgendaInviteeContactLink(link)
    if (!normalized || (allowed && !allowed.has(normalized.email))) return
    const existing = links.get(normalized.email)
    links.set(normalized.email, {
      email: normalized.email,
      label: normalized.label || existing?.label || null,
      hektorContactId: normalized.hektorContactId || existing?.hektorContactId || null,
      source: normalized.source || existing?.source || null,
    })
  }
  current.forEach(addLink)
  next.forEach(addLink)
  return Array.from(links.values())
}

function googleAgendaEventInviteeContacts(event: GoogleCalendarEventLink) {
  const raw = event.metadata_json?.attendee_contacts
  if (!Array.isArray(raw)) return []
  return raw
    .map(normalizeGoogleAgendaInviteeContactLink)
    .filter((item): item is GoogleAgendaInviteeContactLink => Boolean(item))
}

function googleAgendaEventPrimaryInviteeContactLink(event: GoogleCalendarEventLink | null | undefined, attendees?: string[]) {
  if (!event) return null
  const linkedContacts = googleAgendaEventInviteeContacts(event)
  if (linkedContacts[0]) return linkedContacts[0]
  const metadataEmail = normalizeEmail(safeText(event.metadata_json?.contact_email))
  if (metadataEmail) {
    return {
      email: metadataEmail,
      label: safeText(event.metadata_json?.contact_label) || metadataEmail,
      hektorContactId: safeText(event.hektor_contact_id) || safeText(event.metadata_json?.contact_id) || null,
      source: 'agenda_global',
    }
  }
  const firstAttendee = (attendees ?? (Array.isArray(event.attendees_json) ? event.attendees_json : []))
    .map((email) => safeText(email).toLowerCase())
    .find((email) => email.includes('@'))
  if (!firstAttendee) return null
  return {
    email: firstAttendee,
    label: firstAttendee,
    hektorContactId: safeText(event.hektor_contact_id) || null,
    source: 'agenda_global',
  }
}

function googleAgendaInviteeContactMetadata(links: GoogleAgendaInviteeContactLink[], attendees: string[]) {
  return mergeGoogleAgendaInviteeContactLinks(links, [], attendees).map((link) => ({
    email: link.email,
    label: link.label ?? null,
    hektor_contact_id: link.hektorContactId ?? null,
    source: link.source ?? null,
  }))
}

function detailContactAgendaLink(contact: DetailContact, email = detailContactAgendaEmail(contact)): GoogleAgendaInviteeContactLink | null {
  if (!email) return null
  return {
    email,
    label: detailContactAgendaLabel(contact),
    hektorContactId: detailContactDirectoryId(contact),
    source: 'annonce_contact',
  }
}

function contactOptionAgendaLink(contact: MandantContactSearchOption, email = contactOptionAgendaEmail(contact)): GoogleAgendaInviteeContactLink | null {
  if (!email) return null
  return {
    email,
    label: mandantContactOptionTitle(contact),
    hektorContactId: contact.hektor_contact_id,
    source: 'contact_search',
  }
}

function googleAgendaRelationRoleLabel(value: string | null | undefined) {
  const text = safeText(value).replace(/[_-]+/g, ' ').toLowerCase()
  if (!text) return 'Relation annonce'
  if (text.includes('proprietaire') || text.includes('mandant')) return 'Mandant'
  if (text.includes('acquereur')) return 'Acquereur'
  if (text.includes('offre')) return 'Offre'
  return text.charAt(0).toUpperCase() + text.slice(1)
}

function contactInputAgendaLabel(contact: HektorContactIdentityInput) {
  return [contact.civility, contact.firstName, contact.lastName]
    .map((value) => safeText(value))
    .filter(Boolean)
    .join(' ') || safeText(contact.companyName) || safeText(contact.email)
}

type GoogleAgendaWindow = {
  start: string
  end: string
}

type GoogleAgendaViewMode = 'day' | 'week'

function dateInputFromDateTimeLocal(value: string | null | undefined) {
  const date = new Date(value ?? '')
  if (Number.isNaN(date.getTime())) return toDateTimeLocalValue(new Date()).slice(0, 10)
  return toDateTimeLocalValue(date).slice(0, 10)
}

function dateInputToLocalDate(dayValue: string) {
  const date = new Date(`${dayValue || toDateTimeLocalValue(new Date()).slice(0, 10)}T12:00:00`)
  return Number.isNaN(date.getTime()) ? new Date() : date
}

function addDaysToDateInput(dayValue: string, days: number) {
  const date = dateInputToLocalDate(dayValue)
  date.setDate(date.getDate() + days)
  return toDateTimeLocalValue(date).slice(0, 10)
}

function googleAgendaDayRange(dayValue: string) {
  const cleanDay = dayValue || toDateTimeLocalValue(new Date()).slice(0, 10)
  return {
    startAt: `${cleanDay}T08:00`,
    endAt: `${cleanDay}T19:00`,
  }
}

function googleAgendaWeekDays(dayValue: string) {
  const date = dateInputToLocalDate(dayValue)
  const mondayOffset = (date.getDay() + 6) % 7
  date.setDate(date.getDate() - mondayOffset)
  const start = toDateTimeLocalValue(date).slice(0, 10)
  return Array.from({ length: 7 }, (_, index) => addDaysToDateInput(start, index))
}

function googleAgendaPeriodDays(dayValue: string, mode: GoogleAgendaViewMode) {
  return mode === 'week' ? googleAgendaWeekDays(dayValue) : [dayValue || toDateTimeLocalValue(new Date()).slice(0, 10)]
}

function googleAgendaPeriodRange(dayValue: string, mode: GoogleAgendaViewMode) {
  const days = googleAgendaPeriodDays(dayValue, mode)
  const first = days[0] ?? dayValue
  const last = days[days.length - 1] ?? first
  return {
    startAt: `${first}T08:00`,
    endAt: `${last}T19:00`,
  }
}

function googleAgendaDayLabel(dayValue: string) {
  return new Intl.DateTimeFormat('fr-FR', { weekday: 'short', day: '2-digit', month: '2-digit' }).format(dateInputToLocalDate(dayValue))
}

function googleAgendaRangeLabel(dayValue: string, mode: GoogleAgendaViewMode) {
  const days = googleAgendaPeriodDays(dayValue, mode)
  if (mode === 'day') return googleAgendaDayLabel(days[0] ?? dayValue)
  return `${googleAgendaDayLabel(days[0] ?? dayValue)} - ${googleAgendaDayLabel(days[days.length - 1] ?? dayValue)}`
}

function googleAgendaEventOverlapsDay(event: GoogleCalendarEventLink, dayValue: string) {
  const range = googleAgendaDayRange(dayValue)
  const start = new Date(event.starts_at).getTime()
  const end = new Date(event.ends_at).getTime()
  const dayStart = new Date(range.startAt).getTime()
  const dayEnd = new Date(range.endAt).getTime()
  return Number.isFinite(start) && Number.isFinite(end) && end > dayStart && start < dayEnd
}

function googleAgendaEventsForDay(events: GoogleCalendarEventLink[], dayValue: string) {
  return events
    .filter((event) => event.status !== 'deleted' && googleAgendaEventOverlapsDay(event, dayValue))
    .sort((left, right) => new Date(left.starts_at).getTime() - new Date(right.starts_at).getTime())
}

function mergeGoogleCalendarEventLinks(events: GoogleCalendarEventLink[]) {
  const byId = new Map<string, GoogleCalendarEventLink>()
  for (const event of events) {
    byId.set(event.id, event)
  }
  return Array.from(byId.values())
}

function minutesBetweenWindow(window: GoogleAgendaWindow) {
  const start = new Date(window.start)
  const end = new Date(window.end)
  return Math.max(0, Math.round((end.getTime() - start.getTime()) / 60000))
}

function addMinutesIso(value: string, minutes: number) {
  const date = new Date(value)
  date.setMinutes(date.getMinutes() + minutes)
  return date.toISOString()
}

function buildGoogleAgendaSuggestedWindows(freeWindows: GoogleAgendaWindow[], requestedMinutes: number, maxCount = 5) {
  const cleanMinutes = Number.isFinite(requestedMinutes) && requestedMinutes > 0 ? requestedMinutes : 60
  const stepMinutes = 15
  const suggestions: GoogleAgendaWindow[] = []
  for (const window of freeWindows) {
    let cursor = new Date(window.start).getTime()
    const end = new Date(window.end).getTime()
    while (cursor + cleanMinutes * 60000 <= end && suggestions.length < maxCount) {
      const startIso = new Date(cursor).toISOString()
      suggestions.push({ start: startIso, end: addMinutesIso(startIso, cleanMinutes) })
      cursor += stepMinutes * 60000
    }
    if (suggestions.length >= maxCount) break
  }
  return suggestions
}

function buildGoogleAgendaDayWindows(dayValue: string, availability: GoogleCalendarAvailability | null) {
  const range = googleAgendaDayRange(dayValue)
  const dayStart = new Date(range.startAt)
  const dayEnd = new Date(range.endAt)
  const busy = (availability?.busy ?? [])
    .map((slot) => {
      const start = new Date(slot.start ?? '')
      const end = new Date(slot.end ?? '')
      if (Number.isNaN(start.getTime()) || Number.isNaN(end.getTime())) return null
      const clampedStart = new Date(Math.max(start.getTime(), dayStart.getTime()))
      const clampedEnd = new Date(Math.min(end.getTime(), dayEnd.getTime()))
      if (clampedEnd <= clampedStart) return null
      return { start: clampedStart.toISOString(), end: clampedEnd.toISOString() }
    })
    .filter((slot): slot is GoogleAgendaWindow => Boolean(slot))
    .sort((left, right) => new Date(left.start).getTime() - new Date(right.start).getTime())

  const free: GoogleAgendaWindow[] = []
  let cursor = dayStart.getTime()
  for (const slot of busy) {
    const start = new Date(slot.start).getTime()
    const end = new Date(slot.end).getTime()
    if (start > cursor) {
      free.push({ start: new Date(cursor).toISOString(), end: new Date(start).toISOString() })
    }
    cursor = Math.max(cursor, end)
  }
  if (cursor < dayEnd.getTime()) {
    free.push({ start: new Date(cursor).toISOString(), end: dayEnd.toISOString() })
  }
  return { busy, free }
}

type GoogleAgendaCalendarOption = {
  email: string
  label: string
  meta: string
}

function googleAgendaCalendarOptionLabel(option: HektorNegotiatorOption) {
  return option.label || option.email || option.commercialId || 'Negociateur'
}

function sanitizeEmailHtml(html: string, allowRemoteImages: boolean): { clean: string; hadRemoteImages: boolean } {
  let hadRemoteImages = false
  const purified = DOMPurify.sanitize(html, {
    FORBID_TAGS: ['script', 'style', 'iframe', 'object', 'embed', 'form', 'input', 'link', 'meta', 'base'],
    FORBID_ATTR: ['onerror', 'onload', 'onclick', 'onmouseover', 'srcset'],
    ALLOW_DATA_ATTR: false,
    ADD_DATA_URI_TAGS: ['img'],
  })
  if (typeof window === 'undefined' || typeof DOMParser === 'undefined') {
    return { clean: purified, hadRemoteImages }
  }
  const doc = new DOMParser().parseFromString(purified, 'text/html')
  doc.querySelectorAll('img').forEach((img) => {
    const src = img.getAttribute('src') || ''
    if (/^https?:/i.test(src)) {
      hadRemoteImages = true
      if (!allowRemoteImages) {
        img.removeAttribute('src')
        img.setAttribute('data-blocked-src', src)
        img.setAttribute('alt', 'image distante bloquee')
      }
    }
  })
  doc.querySelectorAll('a').forEach((a) => {
    a.setAttribute('target', '_blank')
    a.setAttribute('rel', 'noreferrer noopener')
  })
  return { clean: doc.body.innerHTML, hadRemoteImages }
}

function formatAttachmentSize(size?: number | null) {
  if (!size || size <= 0) return ''
  if (size < 1024) return ` (${size} o)`
  if (size < 1024 * 1024) return ` (${Math.round(size / 1024)} Ko)`
  return ` (${(size / (1024 * 1024)).toFixed(1)} Mo)`
}

function downloadBase64File(contentBase64: string, filename: string, mimeType: string) {
  const byteChars = atob(contentBase64)
  const bytes = new Uint8Array(byteChars.length)
  for (let i = 0; i < byteChars.length; i++) bytes[i] = byteChars.charCodeAt(i)
  const blob = new Blob([bytes], { type: mimeType || 'application/octet-stream' })
  const url = URL.createObjectURL(blob)
  const link = document.createElement('a')
  link.href = url
  link.download = filename || 'piece-jointe'
  document.body.appendChild(link)
  link.click()
  link.remove()
  setTimeout(() => URL.revokeObjectURL(url), 1000)
}

function ContactEmailThreadCard(props: {
  message: GoogleWorkspaceContactEmailMessage
  subjectEmail: string
  contactEmail: string
  hektorContactId?: string | null
}) {
  const { message } = props
  const [expanded, setExpanded] = useState(false)
  const [body, setBody] = useState<GoogleWorkspaceEmailBody | null>(null)
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const [showImages, setShowImages] = useState(false)
  const [downloadingId, setDownloadingId] = useState<string | null>(null)
  const [attachmentError, setAttachmentError] = useState<string | null>(null)

  const internalDateMillis = Number(message.internalDate)
  const internalDateIso =
    Number.isFinite(internalDateMillis) && internalDateMillis > 0 ? new Date(internalDateMillis).toISOString() : null
  const direction = message.direction ?? 'unknown'
  const directionLabel = direction === 'received' ? 'Recu' : direction === 'sent' ? 'Envoye' : 'Email'
  const displayDate = formatDateTime(message.date || internalDateIso)

  const loadBody = useCallback(async () => {
    setLoading(true)
    setError(null)
    try {
      const result = await loadGoogleWorkspaceContactEmailBody({
        subjectEmail: props.subjectEmail,
        messageId: message.id,
        contactEmail: props.contactEmail,
        hektorContactId: props.hektorContactId,
      })
      setBody(result)
    } catch (e) {
      setError(e instanceof Error ? e.message : 'Chargement du contenu impossible.')
    } finally {
      setLoading(false)
    }
  }, [message.id, props.subjectEmail, props.contactEmail, props.hektorContactId])

  const handleToggle = () => {
    const next = !expanded
    setExpanded(next)
    if (next && !body && !loading) void loadBody()
  }

  const handleDownloadAttachment = async (att: GoogleWorkspaceEmailAttachment) => {
    if (!att.attachmentId) return
    setDownloadingId(att.attachmentId)
    setAttachmentError(null)
    try {
      const contentBase64 = await loadGoogleWorkspaceContactEmailAttachment({
        subjectEmail: props.subjectEmail,
        messageId: message.id,
        attachmentId: att.attachmentId,
        contactEmail: props.contactEmail,
        hektorContactId: props.hektorContactId,
      })
      downloadBase64File(contentBase64, att.filename || 'piece-jointe', att.mimeType || '')
    } catch (e) {
      setAttachmentError(e instanceof Error ? e.message : 'Telechargement impossible.')
    } finally {
      setDownloadingId(null)
    }
  }

  const sanitized = useMemo(() => {
    if (!body?.html) return null
    return sanitizeEmailHtml(body.html, showImages)
  }, [body?.html, showImages])

  const attachments: GoogleWorkspaceEmailAttachment[] = body?.attachments ?? []

  return (
    <article className={`contact-email-thread-card is-${direction}`}>
      <div className="contact-email-thread-head">
        <div>
          <span className="contact-email-thread-subject">{message.subject || '(sans objet)'}</span>
          <strong>{displayDate}</strong>
        </div>
        <span className="contact-email-direction-pill">{directionLabel}</span>
      </div>
      <div className="contact-email-thread-meta">
        {message.from ? <span>De : {message.from}</span> : null}
        {message.to ? <span>A : {message.to}</span> : null}
        {message.cc ? <span>Cc : {message.cc}</span> : null}
      </div>
      {!expanded && message.snippet ? <p className="contact-email-thread-snippet">{message.snippet}</p> : null}

      {expanded ? (
        <div className="contact-email-thread-body">
          {loading ? <p className="contact-modern-empty">Chargement du message...</p> : null}
          {error ? <p className="contact-email-thread-error">{error}</p> : null}
          {!loading && !error && body ? (
            <>
              {sanitized && sanitized.hadRemoteImages && !showImages ? (
                <button type="button" className="ghost-button button-subtle" onClick={() => setShowImages(true)}>
                  Afficher les images
                </button>
              ) : null}
              {sanitized ? (
                <div className="contact-email-html" dangerouslySetInnerHTML={{ __html: sanitized.clean }} />
              ) : (
                <pre className="contact-email-text">{body.text || message.snippet || '(message vide)'}</pre>
              )}
              {attachments.length > 0 ? (
                <div className="contact-email-attachments">
                  {attachments.map((att, index) => (
                    <button
                      key={`att-${index}`}
                      type="button"
                      className="contact-email-attachment-pill"
                      onClick={() => void handleDownloadAttachment(att)}
                      disabled={!att.attachmentId || downloadingId === att.attachmentId}
                      title="Telecharger la piece jointe"
                    >
                      📎 {att.filename || 'piece-jointe'}
                      {formatAttachmentSize(att.size)}
                      {downloadingId === att.attachmentId ? ' …' : ''}
                    </button>
                  ))}
                  {attachmentError ? (
                    <span className="contact-email-thread-error">{attachmentError}</span>
                  ) : null}
                </div>
              ) : null}
            </>
          ) : null}
        </div>
      ) : null}

      <div className="contact-email-thread-actions">
        <button type="button" className="ghost-button button-subtle" onClick={handleToggle}>
          {expanded ? 'Reduire' : 'Voir le message'}
        </button>
        {message.gmailUrl ? (
          <a className="ghost-button button-subtle" href={message.gmailUrl} target="_blank" rel="noreferrer">
            Ouvrir Gmail
          </a>
        ) : null}
      </div>
    </article>
  )
}

function resolveGoogleWorkspaceCalendarEmail(input: {
  emails?: Array<string | null | undefined>
  commercialId?: string | number | null
  label?: string | null
  hektorNegotiators?: HektorNegotiatorOption[]
}) {
  const workspaceEmail = (input.emails ?? [])
    .map((email) => normalizeEmail(email))
    .find((email) => isGoogleWorkspaceEmail(email))
  if (workspaceEmail) return workspaceEmail

  const commercialId = safeText(input.commercialId)
  const label = safeText(input.label).toLowerCase()
  const match = (input.hektorNegotiators ?? []).find((option) => {
    const optionEmail = normalizeEmail(option.email)
    if (!isGoogleWorkspaceEmail(optionEmail)) return false
    if (commercialId && [option.idUser, option.commercialId, option.hektorNegociateurId].map(safeText).includes(commercialId)) return true
    return Boolean(label && safeText(option.label).toLowerCase() === label)
  })
  const matchedEmail = normalizeEmail(match?.email)
  if (matchedEmail) return matchedEmail

  const fallbackEmail = normalizeEmail((input.emails ?? []).find(Boolean))
  const fallbackLocalPart = fallbackEmail.split('@')[0] ?? ''
  if (fallbackLocalPart && /[._-]/.test(fallbackLocalPart)) {
    return `${fallbackLocalPart.replace(/[-_]+/g, '.')}@${googleWorkspaceDomain}`
  }
  return fallbackEmail
}

function googleAgendaDisplayNameFromEmail(email: string | null | undefined) {
  const normalized = normalizeEmail(email)
  if (!normalized) return ''
  const localPart = normalized.split('@')[0] ?? ''
  const words = localPart
    .replace(/[._-]+/g, ' ')
    .split(' ')
    .map((part) => part.trim())
    .filter(Boolean)
  if (words.length === 0) return normalized
  return words.map((word) => word.charAt(0).toUpperCase() + word.slice(1)).join(' ')
}

function googleAgendaCalendarOptions(input: {
  defaultEmail?: string | null
  hektorNegotiators?: HektorNegotiatorOption[]
  canSelectTeam?: boolean
  userLabel?: string | null
}): GoogleAgendaCalendarOption[] {
  const byEmail = new Map<string, GoogleAgendaCalendarOption>()
  const add = (email: string | null | undefined, label: string | null | undefined, meta: string | null | undefined) => {
    const normalized = normalizeEmail(email)
    if (!normalized || byEmail.has(normalized)) return
    byEmail.set(normalized, {
      email: normalized,
      label: safeText(label) || normalized,
      meta: safeText(meta) || normalized,
    })
  }
  const defaultEmail = normalizeEmail(input.defaultEmail)
  if (defaultEmail) add(defaultEmail, input.userLabel || 'Mon agenda', 'Agenda principal')
  const options = input.hektorNegotiators ?? []
  options
    .filter((option) => input.canSelectTeam || normalizeEmail(option.email) === defaultEmail)
    .forEach((option) => add(option.email, googleAgendaCalendarOptionLabel(option), option.agenceNom || option.email))
  return Array.from(byEmail.values()).sort((left, right) => left.label.localeCompare(right.label, 'fr'))
}

function eventTypeLabel(value: GoogleCalendarEventLink['event_type'] | string | null | undefined) {
  return googleAgendaEventTypeOptions.find((option) => option.value === value)?.label ?? (safeText(value) || 'RDV')
}

function googleAgendaPeriodFreeMinutes(days: Array<{ free: GoogleAgendaWindow[] }>) {
  return days.reduce((sum, day) => sum + day.free.reduce((daySum, slot) => daySum + minutesBetweenWindow(slot), 0), 0)
}

const googleAgendaTimelineStartHour = 8
const googleAgendaTimelineEndHour = 19
const googleAgendaTimelineTotalMinutes = (googleAgendaTimelineEndHour - googleAgendaTimelineStartHour) * 60
const googleAgendaTimelineHours = Array.from(
  { length: googleAgendaTimelineEndHour - googleAgendaTimelineStartHour + 1 },
  (_, index) => googleAgendaTimelineStartHour + index,
)

function googleAgendaTimelineBlockStyle(dayValue: string, startValue: string | null | undefined, endValue: string | null | undefined) {
  const range = googleAgendaDayRange(dayValue)
  const dayStart = new Date(range.startAt).getTime()
  const dayEnd = new Date(range.endAt).getTime()
  const start = new Date(startValue ?? '').getTime()
  const end = new Date(endValue ?? '').getTime()
  const cleanStart = Number.isFinite(start) ? Math.max(dayStart, Math.min(start, dayEnd)) : dayStart
  const cleanEnd = Number.isFinite(end) ? Math.max(dayStart, Math.min(end, dayEnd)) : cleanStart + 30 * 60000
  const topMinutes = Math.max(0, Math.round((cleanStart - dayStart) / 60000))
  const durationMinutes = Math.max(18, Math.round((Math.max(cleanEnd, cleanStart + 18 * 60000) - cleanStart) / 60000))
  const top = Math.min(100, Math.max(0, (topMinutes / googleAgendaTimelineTotalMinutes) * 100))
  const height = Math.min(100 - top, Math.max(3.4, (durationMinutes / googleAgendaTimelineTotalMinutes) * 100))
  return {
    top: `${top}%`,
    height: `${height}%`,
  }
}

function GoogleAgendaGlobalScreen(props: {
  defaultCalendarEmail?: string | null
  userLabel?: string | null
  hektorNegotiators?: HektorNegotiatorOption[]
  profileRole?: UserProfile['role'] | null
  canManageContacts?: boolean
  hektorUserEmail?: string | null
  hektorUserId?: string | null
  sessionEmail?: string | null
  onOpenDossier?: (appDossierId: number) => void
  onOpenContact?: (contactId: string) => void
  onHektorActionJobCreated?: (job: ConsoleJob) => void
}) {
  const canSelectTeam = props.profileRole === 'admin' || props.profileRole === 'manager'
  const defaultEmail = normalizeEmail(props.defaultCalendarEmail)
  const calendarOptions = useMemo(() => googleAgendaCalendarOptions({
    defaultEmail,
    hektorNegotiators: props.hektorNegotiators,
    canSelectTeam,
    userLabel: props.userLabel,
  }), [canSelectTeam, defaultEmail, props.hektorNegotiators, props.userLabel])
  const [calendarEmail, setCalendarEmail] = useState(defaultEmail)
  const [agendaDate, setAgendaDate] = useState(dateInputFromDateTimeLocal(defaultGoogleAgendaStartValue()))
  const [agendaMode, setAgendaMode] = useState<GoogleAgendaViewMode>('day')
  const [availability, setAvailability] = useState<GoogleCalendarAvailability | null>(null)
  const [linkedEvents, setLinkedEvents] = useState<GoogleCalendarEventLink[]>([])
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const [createSlot, setCreateSlot] = useState<GoogleAgendaWindow | null>(null)
  const [editingEvent, setEditingEvent] = useState<GoogleCalendarEventLink | null>(null)
  const [deletingId, setDeletingId] = useState<string | null>(null)
  const [printingId, setPrintingId] = useState<string | null>(null)

  useEffect(() => {
    if (!calendarEmail && defaultEmail) setCalendarEmail(defaultEmail)
  }, [calendarEmail, defaultEmail])

  useEffect(() => {
    setAvailability(null)
    setLinkedEvents([])
    setError(null)
  }, [agendaDate, agendaMode, calendarEmail])

  const canUseCalendarEmail = calendarEmail.trim().toLowerCase().endsWith(`@${googleWorkspaceDomain}`)
  const periodRange = googleAgendaPeriodRange(agendaDate, agendaMode)
  const agendaPeriodDays = googleAgendaPeriodDays(agendaDate, agendaMode)
  const activeEvents = linkedEvents.filter((item) => item.status !== 'deleted')
  const agendaDayPlans = agendaPeriodDays.map((day) => ({
    day,
    label: googleAgendaDayLabel(day),
    events: googleAgendaEventsForDay(activeEvents, day),
    ...buildGoogleAgendaDayWindows(day, availability),
  }))
  const visibleEventCount = agendaDayPlans.reduce((sum, day) => sum + day.events.length, 0)
  const busyCount = agendaDayPlans.reduce((sum, day) => sum + day.busy.length, 0)
  const freeMinutes = googleAgendaPeriodFreeMinutes(agendaDayPlans)
  const suggestedWindows = buildGoogleAgendaSuggestedWindows(agendaDayPlans.flatMap((day) => day.free), 60, 6)
  const selectedCalendar = calendarOptions.find((option) => option.email === normalizeEmail(calendarEmail))
  const calendarDisplayName = selectedCalendar?.label || googleAgendaDisplayNameFromEmail(calendarEmail) || 'Agenda Google'
  const calendarDisplayMeta = selectedCalendar?.meta || normalizeEmail(calendarEmail) || googleAgendaRangeLabel(agendaDate, agendaMode)

  async function handleLoadGlobalAgenda() {
    setLoading(true)
    setError(null)
    setAvailability(null)
    setLinkedEvents([])
    try {
      if (!canUseCalendarEmail) throw new Error('Agenda Google Workspace requis')
      const [availabilityResult, eventRows] = await Promise.all([
        checkGoogleCalendarAvailability({
          subjectEmail: calendarEmail,
          startAt: periodRange.startAt,
          endAt: periodRange.endAt,
        }),
        loadGoogleCalendarEventLinks({
          calendarEmail,
          startAt: periodRange.startAt,
          endAt: periodRange.endAt,
          limit: 100,
        }),
      ])
      if (!availabilityResult.ok) throw new Error('Chargement occupation agenda impossible')
      setAvailability(availabilityResult)
      setLinkedEvents(eventRows)
    } catch (loadError) {
      setError(loadError instanceof Error ? loadError.message : 'Chargement agenda impossible')
    } finally {
      setLoading(false)
    }
  }

  async function handleDeleteGlobalAgendaEvent(eventLink: GoogleCalendarEventLink) {
    if (!window.confirm(`Supprimer ce RDV Google : ${eventLink.summary} ?`)) return
    setDeletingId(eventLink.id)
    setError(null)
    try {
      await deleteGoogleCalendarEvent(eventLink.id, { sendUpdates: 'all' })
      await handleLoadGlobalAgenda()
    } catch (deleteError) {
      setError(deleteError instanceof Error ? deleteError.message : 'Suppression RDV Google impossible')
    } finally {
      setDeletingId(null)
    }
  }

  async function handlePrintGlobalAgendaVisitVoucher(eventLink: GoogleCalendarEventLink) {
    const voucherContact = visitVoucherContactFromGoogleEvent(eventLink)
    const voucherRelations = visitVoucherRelationsFromGoogleEvent(eventLink)
    const printWindow = window.open('', '_blank')
    writeVisitVoucherWindow(printWindow, visitVoucherLoadingHtml())
    setPrintingId(eventLink.id)
    setError(null)
    let photoUrl: string | null = null
    try {
      photoUrl = await loadVisitVoucherPhotoUrl(eventLink, voucherRelations)
    } catch (photoError) {
      console.warn('Visit voucher photo loading failed', photoError)
    } finally {
      openVisitVoucherPrint(voucherContact, eventLink, voucherRelations, photoUrl, printWindow)
      setPrintingId(null)
    }
  }

  return (
    <section className="google-agenda-global-screen">
      <section className="google-agenda-panel google-agenda-global-toolbar">
        <div className="google-agenda-panel-head">
          <span>Agenda global</span>
          <strong>{calendarDisplayName}</strong>
          <small>{googleAgendaRangeLabel(agendaDate, agendaMode)}</small>
        </div>
        <div className="google-agenda-global-controls">
          <label className="filter-field">
            <span>Agenda</span>
            <input list="google-agenda-global-calendar-options" value={calendarEmail} onChange={(event) => setCalendarEmail(event.target.value)} placeholder={`nego@${googleWorkspaceDomain}`} />
            <datalist id="google-agenda-global-calendar-options">
              {calendarOptions.map((option) => <option key={option.email} value={option.email}>{option.label}</option>)}
            </datalist>
          </label>
          <label className="filter-field">
            <span>Date</span>
            <input value={agendaDate} onChange={(event) => setAgendaDate(event.target.value)} type="date" />
          </label>
          <div className="google-agenda-view-toggle" role="group" aria-label="Vue agenda globale">
            <button className={agendaMode === 'day' ? 'is-active' : ''} type="button" onClick={() => setAgendaMode('day')}>Jour</button>
            <button className={agendaMode === 'week' ? 'is-active' : ''} type="button" onClick={() => setAgendaMode('week')}>Semaine</button>
          </div>
          <button className="ghost-button button-primary" type="button" onClick={() => void handleLoadGlobalAgenda()} disabled={loading || !canUseCalendarEmail}>
            {loading ? 'Chargement...' : 'Actualiser'}
          </button>
        </div>
        {!canUseCalendarEmail ? <p className="google-agenda-error">Agenda Google Workspace requis.</p> : null}
        {error ? <p className="google-agenda-error">{error}</p> : null}
      </section>

      <div className="google-agenda-modal-meta google-agenda-global-meta">
        <span className="google-agenda-kpi is-calendar" title={calendarEmail || undefined}><strong>Agenda</strong>{calendarDisplayName}</span>
        <span className="google-agenda-kpi is-period"><strong>Periode</strong>{googleAgendaRangeLabel(agendaDate, agendaMode)}</span>
        <span className="google-agenda-kpi is-gti"><strong>RDV GTI</strong>{visibleEventCount}</span>
        <span className="google-agenda-kpi is-busy"><strong>Google occupe</strong>{busyCount} creneau{busyCount > 1 ? 'x' : ''}</span>
        <span className="google-agenda-kpi is-free"><strong>Libre</strong>{availability ? `${Math.round(freeMinutes / 60)} h` : '-'}</span>
      </div>

      <section className="google-agenda-panel google-agenda-global-board">
        <div className="google-agenda-panel-head google-agenda-day-head">
          <div>
            <span>Planning</span>
            <strong>{agendaMode === 'week' ? 'Semaine' : 'Journee'}</strong>
            <small>{calendarDisplayMeta}</small>
          </div>
        </div>
        {availability ? (
          <>
            <div className="google-agenda-global-suggestions">
              <div>
                <span className="detail-label">Creneaux rapides</span>
                <strong>{suggestedWindows.length ? 'Disponibilites de 1 h' : 'Aucune disponibilite de 1 h'}</strong>
              </div>
              {suggestedWindows.length > 0 ? (
                <div className="google-agenda-global-suggestion-list">
                  {suggestedWindows.map((slot, index) => (
                    <button key={`global-suggestion-${slot.start}-${slot.end}`} className={`google-agenda-suggestion${index === 0 ? ' is-best' : ''}`} type="button" onClick={() => setCreateSlot(slot)}>
                      <strong>{index === 0 ? 'Meilleur creneau' : `Option ${index + 1}`}</strong>
                      <span>{formatDateTime(slot.start)} - {formatTimeOnly(slot.end)}</span>
                    </button>
                  ))}
                </div>
              ) : <p className="empty-state">Aucun creneau libre assez long sur la periode chargee.</p>}
            </div>
            <div
              className={`google-agenda-global-calendar google-agenda-timeline is-${agendaMode}`}
              style={{ gridTemplateColumns: `74px repeat(${agendaDayPlans.length}, minmax(${agendaMode === 'week' ? '168px' : '420px'}, 1fr))` }}
            >
              <div className="google-agenda-timeline-corner">
                <strong>08-19</strong>
              </div>
              {agendaDayPlans.map((plan) => {
                const dayFreeMinutes = plan.free.reduce((sum, slot) => sum + minutesBetweenWindow(slot), 0)
                return (
                  <div key={`global-agenda-head-${plan.day}`} className={`google-agenda-timeline-day-head${plan.day === agendaDate ? ' is-selected-day' : ''}`}>
                    <strong>{plan.label}</strong>
                    <span>{Math.round(dayFreeMinutes / 60)} h libres</span>
                    <small>{plan.events.length} GTI - {plan.busy.length} occupe</small>
                  </div>
                )
              })}
              <div className="google-agenda-timeline-hours" aria-hidden="true">
                {googleAgendaTimelineHours.map((hour) => (
                  <span
                    key={`global-agenda-hour-${hour}`}
                    style={{ top: `${((hour - googleAgendaTimelineStartHour) / (googleAgendaTimelineEndHour - googleAgendaTimelineStartHour)) * 100}%` }}
                  >
                    {String(hour).padStart(2, '0')}:00
                  </span>
                ))}
              </div>
              {agendaDayPlans.map((plan) => (
                <div key={`global-agenda-track-${plan.day}`} className={`google-agenda-timeline-track${plan.day === agendaDate ? ' is-selected-day' : ''}`}>
                  {plan.free.map((slot) => (
                    <button
                      key={`global-free-${plan.day}-${slot.start}-${slot.end}`}
                      className="google-agenda-timeline-block google-agenda-timeline-free"
                      type="button"
                      style={googleAgendaTimelineBlockStyle(plan.day, slot.start, slot.end)}
                      onClick={() => setCreateSlot(slot)}
                      disabled={!canUseCalendarEmail}
                    >
                      <strong>{formatTimeOnly(slot.start)} - {formatTimeOnly(slot.end)}</strong>
                      <span>{minutesBetweenWindow(slot)} min libres</span>
                    </button>
                  ))}
                  {plan.busy.map((slot) => (
                    <div
                      key={`global-busy-${plan.day}-${slot.start}-${slot.end}`}
                      className="google-agenda-timeline-block google-agenda-timeline-busy"
                      style={googleAgendaTimelineBlockStyle(plan.day, slot.start, slot.end)}
                    >
                      <strong>{formatTimeOnly(slot.start)} - {formatTimeOnly(slot.end)}</strong>
                      <span>Occupe Google</span>
                    </div>
                  ))}
                  {plan.events.map((item) => (
                    <article
                      key={`global-event-${plan.day}-${item.id}`}
                      className="google-agenda-timeline-block google-agenda-timeline-event"
                      style={googleAgendaTimelineBlockStyle(plan.day, item.starts_at, item.ends_at)}
                    >
                      <button className="google-agenda-timeline-event-main" type="button" onClick={() => setEditingEvent(item)}>
                        <strong>{formatTimeOnly(item.starts_at)} - {formatTimeOnly(item.ends_at)}</strong>
                        <span>{item.summary}</span>
                        <small>{eventTypeLabel(item.event_type)}{item.location ? ` - ${item.location}` : ''}</small>
                      </button>
                      <div className="google-agenda-timeline-event-actions">
                        {item.app_dossier_id && props.onOpenDossier ? (
                          <button className="ghost-button button-subtle" type="button" onClick={() => props.onOpenDossier?.(Number(item.app_dossier_id))}>Fiche</button>
                        ) : null}
                        {item.hektor_contact_id && props.onOpenContact ? (
                          <button className="ghost-button button-subtle" type="button" onClick={() => props.onOpenContact?.(String(item.hektor_contact_id))}>Contact</button>
                        ) : null}
                        {canPrintVisitVoucher(item) ? (
                          <button className="ghost-button button-subtle" type="button" onClick={() => void handlePrintGlobalAgendaVisitVoucher(item)} disabled={deletingId === item.id || printingId === item.id}>
                            {printingId === item.id ? '...' : 'Bon de visite'}
                          </button>
                        ) : null}
                        {item.google_html_link ? <a className="ghost-button button-subtle" href={item.google_html_link} target="_blank" rel="noreferrer">Google</a> : null}
                        <button className="ghost-button button-subtle" type="button" onClick={() => void handleDeleteGlobalAgendaEvent(item)} disabled={deletingId === item.id}>
                          {deletingId === item.id ? '...' : 'Suppr.'}
                        </button>
                      </div>
                    </article>
                  ))}
                </div>
              ))}
            </div>
          </>
        ) : <p className="empty-state">{loading ? 'Chargement agenda...' : 'Agenda non charge.'}</p>}
      </section>
      {createSlot ? (
        <GoogleAgendaGlobalEventModal
          calendarEmail={calendarEmail}
          slot={createSlot}
          hektorNegotiators={props.hektorNegotiators}
          canManageContacts={props.canManageContacts}
          hektorUserEmail={props.hektorUserEmail}
          hektorUserId={props.hektorUserId}
          profileRole={props.profileRole}
          sessionEmail={props.sessionEmail}
          onHektorActionJobCreated={props.onHektorActionJobCreated}
          onClose={() => setCreateSlot(null)}
          onCreated={() => {
            setCreateSlot(null)
            void handleLoadGlobalAgenda()
          }}
        />
      ) : null}
      {editingEvent ? (
        <GoogleAgendaGlobalEventModal
          calendarEmail={editingEvent.google_calendar_email || calendarEmail}
          slot={{ start: editingEvent.starts_at, end: editingEvent.ends_at }}
          editingEvent={editingEvent}
          hektorNegotiators={props.hektorNegotiators}
          canManageContacts={props.canManageContacts}
          hektorUserEmail={props.hektorUserEmail}
          hektorUserId={props.hektorUserId}
          profileRole={props.profileRole}
          sessionEmail={props.sessionEmail}
          onHektorActionJobCreated={props.onHektorActionJobCreated}
          onClose={() => setEditingEvent(null)}
          onUpdated={() => {
            setEditingEvent(null)
            void handleLoadGlobalAgenda()
          }}
        />
      ) : null}
    </section>
  )
}

function GoogleAgendaGlobalEventModal(props: {
  calendarEmail: string
  slot: GoogleAgendaWindow
  editingEvent?: GoogleCalendarEventLink | null
  hektorNegotiators?: HektorNegotiatorOption[]
  canManageContacts?: boolean
  hektorUserEmail?: string | null
  hektorUserId?: string | null
  profileRole?: UserProfile['role'] | null
  sessionEmail?: string | null
  presetAnnonce?: OwnerAnnonceSearchOption | null
  presetContactLink?: GoogleAgendaInviteeContactLink | null
  presetEventType?: GoogleCalendarEventLink['event_type']
  presetSummary?: string | null
  presetLocation?: string | null
  presetMetadata?: Record<string, unknown>
  overlayClassName?: string
  onClose: () => void
  onCreated?: (event: GoogleCalendarEventLink | null) => void
  onUpdated?: (event: GoogleCalendarEventLink | null) => void
  onHektorActionJobCreated?: (job: ConsoleJob) => void
}) {
  const editingEvent = props.editingEvent ?? null
  const isEditingGoogleGlobalEvent = Boolean(editingEvent)
  const modalCalendarEmail = normalizeEmail(editingEvent?.google_calendar_email) || props.calendarEmail
  const defaultStartAt = editingEvent
    ? toExistingDateTimeLocalValue(editingEvent.starts_at, defaultGoogleAgendaStartValue())
    : toExistingDateTimeLocalValue(props.slot.start, defaultGoogleAgendaStartValue())
  const slotMinutes = minutesBetweenWindow(props.slot)
  const defaultDuration = editingEvent
    ? minutesBetweenDateTimes(editingEvent.starts_at, editingEvent.ends_at)
    : String(Math.max(30, Math.min(60, slotMinutes || 60)))
  const initialAttendees = Array.isArray(editingEvent?.attendees_json) ? editingEvent.attendees_json : []
  const initialAnnonce = googleAgendaEventAnnonceOption(editingEvent, [])
  const initialContactLink = googleAgendaEventPrimaryInviteeContactLink(editingEvent, initialAttendees)
  const agendaOwner = findContactHektorOption(props.hektorNegotiators ?? [], { email: modalCalendarEmail })
  const [eventType, setEventType] = useState<GoogleCalendarEventLink['event_type']>(editingEvent?.event_type ?? props.presetEventType ?? 'visite')
  const [selectedAnnonce, setSelectedAnnonce] = useState<OwnerAnnonceSearchOption | null>(() => initialAnnonce ?? props.presetAnnonce ?? null)
  const [annonceSearch, setAnnonceSearch] = useState('')
  const [annonceOptions, setAnnonceOptions] = useState<OwnerAnnonceSearchOption[]>([])
  const [annonceLoading, setAnnonceLoading] = useState(false)
  const [annonceError, setAnnonceError] = useState<string | null>(null)
  const [selectedContact, setSelectedContact] = useState<MandantContactSearchOption | null>(null)
  const [contactSearch, setContactSearch] = useState('')
  const [contactOptions, setContactOptions] = useState<MandantContactSearchOption[]>([])
  const [contactSearchLoading, setContactSearchLoading] = useState(false)
  const [contactSearchError, setContactSearchError] = useState<string | null>(null)
  const [contactCreateOpen, setContactCreateOpen] = useState(false)
  const [createdContactLink, setCreatedContactLink] = useState<GoogleAgendaInviteeContactLink | null>(() => initialContactLink ?? props.presetContactLink ?? null)
  const [linkedRelationContactOptions, setLinkedRelationContactOptions] = useState<AnnonceContactInviteeOption[]>([])
  const [linkedRelationContactsLoading, setLinkedRelationContactsLoading] = useState(false)
  const [linkedRelationContactsError, setLinkedRelationContactsError] = useState<string | null>(null)
  const [summary, setSummary] = useState(editingEvent?.summary ?? props.presetSummary ?? '')
  const [startAt, setStartAt] = useState(defaultStartAt)
  const [durationMinutes, setDurationMinutes] = useState(defaultDuration)
  const [location, setLocation] = useState(editingEvent?.location ?? props.presetLocation ?? '')
  const [attendeesText, setAttendeesText] = useState(joinEmailList(initialAttendees))
  const [attendeeContactLinks, setAttendeeContactLinks] = useState<GoogleAgendaInviteeContactLink[]>(() => (
    mergeGoogleAgendaInviteeContactLinks(
      editingEvent ? googleAgendaEventInviteeContacts(editingEvent) : [],
      (initialContactLink ?? props.presetContactLink) ? [(initialContactLink ?? props.presetContactLink)!] : [],
      initialAttendees,
    )
  ))
  const [description, setDescription] = useState('')
  const [pending, setPending] = useState(false)
  const [availabilityPending, setAvailabilityPending] = useState(false)
  const [availability, setAvailability] = useState<GoogleCalendarAvailability | null>(null)
  const [message, setMessage] = useState<string | null>(null)
  const [error, setError] = useState<string | null>(null)

  const canUseCalendarEmail = modalCalendarEmail.trim().toLowerCase().endsWith(`@${googleWorkspaceDomain}`)
  const isVisit = eventType === 'visite'
  const hasCustomDuration = durationMinutes && !googleAgendaDurationOptions.includes(durationMinutes)
  const availabilityBusy = availability?.busy ?? []
  const attendeeEmails = splitEmailList(attendeesText)
  const selectedContactEmail = selectedContact ? contactOptionAgendaEmail(selectedContact) : ''
  const selectedContactLabel = selectedContact ? mandantContactOptionTitle(selectedContact) : ''
  const activeContactEmail = selectedContactEmail || createdContactLink?.email || ''
  const activeContactLabel = selectedContactLabel || createdContactLink?.label || ''
  const selectedAnnonceTitle = selectedAnnonce ? ownerAnnonceOptionTitle(selectedAnnonce) : ''
  const activeContactLink = selectedContact
    ? contactOptionAgendaLink(selectedContact, selectedContactEmail)
    : createdContactLink
  const defaultContactHektorUserEmail = normalizeEmail(agendaOwner?.email) || normalizeEmail(modalCalendarEmail) || normalizeEmail(props.hektorUserEmail)
  const defaultContactHektorUserId = agendaOwner?.idUser || props.hektorUserId || null
  const canSubmit = canUseCalendarEmail
    && Boolean(summary.trim())
    && (!isVisit || (Boolean(selectedAnnonce) && Boolean(activeContactEmail)))

  const linkedAgendaContacts = useMemo(() => {
    const contactsByKey = new Map<string, GoogleAgendaLinkedInviteeOption>()
    linkedRelationContactOptions.forEach((option) => {
      const email = contactOptionAgendaEmail(option)
      const relationLabel = googleAgendaRelationRoleLabel(option.role_contact)
      const hektorContactId = safeText(option.hektor_contact_id)
      const key = hektorContactId ? `contact-${hektorContactId}` : email ? `email-${email}` : `label-${option.display_name}-${contactsByKey.size}`
      contactsByKey.set(key, {
        key,
        label: mandantContactOptionTitle(option),
        email,
        meta: `${relationLabel} - ${email || option.phone_primary || option.phone_secondary || 'Email absent'}`,
        hektorContactId: hektorContactId || null,
        link: contactOptionAgendaLink(option, email),
      })
    })
    return Array.from(contactsByKey.values())
  }, [linkedRelationContactOptions])

  const annonceScope = useMemo<DataScope | null>(() => {
    const negotiatorEmail = normalizeEmail(agendaOwner?.email) || normalizeEmail(modalCalendarEmail)
    const agencyName = safeText(agendaOwner?.agenceNom)
    if (agencyName) return { agencyName, negotiatorEmail: negotiatorEmail || null }
    return negotiatorEmail.endsWith(`@${googleWorkspaceDomain}`) ? { negotiatorEmail } : null
  }, [agendaOwner?.agenceNom, agendaOwner?.email, modalCalendarEmail])

  const contactScope = useMemo<DataScope | null>(() => {
    const negotiatorEmail = normalizeEmail(agendaOwner?.email) || normalizeEmail(modalCalendarEmail)
    const agencyName = safeText(selectedAnnonce?.agence_nom) || safeText(agendaOwner?.agenceNom)
    if (agencyName) return { agencyName, negotiatorEmail: negotiatorEmail || null }
    return negotiatorEmail.endsWith(`@${googleWorkspaceDomain}`) ? { negotiatorEmail } : null
  }, [agendaOwner?.agenceNom, agendaOwner?.email, modalCalendarEmail, selectedAnnonce?.agence_nom])
  const annonceScopeLabel = annonceScope?.agencyName
    ? `Biens actifs de l'agence ${annonceScope.agencyName}`
    : annonceScope?.negotiatorEmail
      ? `Biens actifs de ${annonceScope.negotiatorEmail}`
      : 'Biens actifs accessibles'
  const contactScopeLabel = contactScope?.agencyName
    ? `Contacts de l'agence ${contactScope.agencyName}`
    : contactScope?.negotiatorEmail
      ? `Contacts de ${contactScope.negotiatorEmail}`
      : 'Contacts accessibles'

  useEffect(() => {
    if (isEditingGoogleGlobalEvent) return
    const label = googleAgendaEventTypeOptions.find((option) => option.value === eventType)?.label ?? 'RDV'
    const parts = [
      `${label} GTI`,
      selectedAnnonceTitle,
      activeContactLabel,
    ].filter(Boolean)
    setSummary(parts.join(' - '))
  }, [activeContactLabel, eventType, isEditingGoogleGlobalEvent, selectedAnnonceTitle])

  useEffect(() => {
    if (isEditingGoogleGlobalEvent) return
    setDescription([
      'RDV cree depuis Agenda global GTI.',
      activeContactLabel ? `Contact : ${activeContactLabel}` : '',
      selectedContact?.hektor_contact_id ? `Contact Hektor : ${selectedContact.hektor_contact_id}` : '',
      activeContactEmail ? `Email contact : ${activeContactEmail}` : '',
      selectedAnnonce ? `Bien : ${selectedAnnonceTitle}` : '',
      selectedAnnonce?.hektor_annonce_id ? `Annonce Hektor : ${selectedAnnonce.hektor_annonce_id}` : '',
      selectedAnnonce?.numero_dossier ? `Dossier : ${selectedAnnonce.numero_dossier}` : '',
      selectedAnnonce?.numero_mandat ? `Mandat : ${selectedAnnonce.numero_mandat}` : '',
      isVisit ? 'Preparation bon de visite : contact et bien lies au RDV.' : '',
    ].filter(Boolean).join('\n'))
  }, [activeContactEmail, activeContactLabel, isEditingGoogleGlobalEvent, isVisit, selectedAnnonce, selectedAnnonceTitle, selectedContact])

  useEffect(() => {
    setAvailability(null)
  }, [durationMinutes, startAt])

  useEffect(() => {
    if (selectedAnnonce) {
      const nextLocation = [
        selectedAnnonce.adresse_privee_listing || selectedAnnonce.adresse_detail,
        selectedAnnonce.code_postal,
        selectedAnnonce.ville,
      ].filter(Boolean).join(' ')
      if (nextLocation) setLocation(nextLocation)
    }
  }, [selectedAnnonce])

  useEffect(() => {
    if (!selectedAnnonce) {
      setLinkedRelationContactOptions([])
      setLinkedRelationContactsLoading(false)
      setLinkedRelationContactsError(null)
      return
    }
    let cancelled = false
    setLinkedRelationContactsLoading(true)
    setLinkedRelationContactsError(null)
    void loadAnnonceContactInvitees({
      appDossierId: selectedAnnonce.app_dossier_id,
      hektorAnnonceId: selectedAnnonce.hektor_annonce_id,
      limit: 24,
    })
      .then((rows) => {
        if (!cancelled) setLinkedRelationContactOptions(rows)
      })
      .catch((relationError) => {
        if (cancelled) return
        setLinkedRelationContactOptions([])
        setLinkedRelationContactsError(relationError instanceof Error ? relationError.message : 'Contacts lies impossibles a charger.')
      })
      .finally(() => {
        if (!cancelled) setLinkedRelationContactsLoading(false)
      })
    return () => {
      cancelled = true
    }
  }, [selectedAnnonce])

  useEffect(() => {
    const search = annonceSearch.trim()
    const minSearchLength = /^\d+$/.test(search) ? 1 : 3
    if (search.length < minSearchLength) {
      setAnnonceOptions([])
      setAnnonceLoading(false)
      setAnnonceError(null)
      return
    }
    let cancelled = false
    setAnnonceLoading(true)
    setAnnonceError(null)
    const handle = window.setTimeout(async () => {
      try {
        const rows = await searchOwnerAnnonceOptions({ search, scope: annonceScope, limit: 8, activeListingsOnly: true })
        if (!cancelled) setAnnonceOptions(rows)
      } catch (searchError) {
        if (cancelled) return
        setAnnonceOptions([])
        setAnnonceError(searchError instanceof Error ? searchError.message : 'Recherche bien impossible.')
      } finally {
        if (!cancelled) setAnnonceLoading(false)
      }
    }, 260)
    return () => {
      cancelled = true
      window.clearTimeout(handle)
    }
  }, [annonceScope, annonceSearch])

  useEffect(() => {
    const search = contactSearch.trim()
    const minSearchLength = /^\d+$/.test(search) ? 1 : 3
    if (search.length < minSearchLength) {
      setContactOptions([])
      setContactSearchLoading(false)
      setContactSearchError(null)
      return
    }
    let cancelled = false
    setContactSearchLoading(true)
    setContactSearchError(null)
    const handle = window.setTimeout(async () => {
      try {
        const rows = await searchMandantContactOptions({ search, scope: contactScope, limit: 8 })
        if (!cancelled) setContactOptions(rows)
      } catch (searchError) {
        if (cancelled) return
        setContactOptions([])
        setContactSearchError(searchError instanceof Error ? searchError.message : 'Recherche contact impossible.')
      } finally {
        if (!cancelled) setContactSearchLoading(false)
      }
    }, 260)
    return () => {
      cancelled = true
      window.clearTimeout(handle)
    }
  }, [contactScope, contactSearch])

  function handleSelectAnnonce(option: OwnerAnnonceSearchOption) {
    setSelectedAnnonce(option)
    setAnnonceSearch(ownerAnnonceOptionTitle(option))
    setAnnonceOptions([])
    setAnnonceError(null)
  }

  function handleSelectContact(option: MandantContactSearchOption) {
    setSelectedContact(option)
    setCreatedContactLink(null)
    setContactSearch(mandantContactOptionTitle(option))
    setContactOptions([])
    setContactSearchError(null)
    const email = contactOptionAgendaEmail(option)
    const link = contactOptionAgendaLink(option, email)
    if (email) {
      const nextAttendees = splitEmailList(joinEmailList([...splitEmailList(attendeesText), email]))
      setAttendeesText(joinEmailList(nextAttendees))
      setAttendeeContactLinks((current) => mergeGoogleAgendaInviteeContactLinks(current, link ? [link] : [], nextAttendees))
    }
  }

  function handleChangeSelectedContact() {
    const emailToRemove = activeContactEmail
    setSelectedContact(null)
    setCreatedContactLink(null)
    setContactSearch('')
    setContactOptions([])
    setContactSearchError(null)
    setContactSearchLoading(false)
    if (emailToRemove) {
      const nextAttendees = attendeeEmails.filter((email) => email !== emailToRemove)
      setAttendeesText(joinEmailList(nextAttendees))
      setAttendeeContactLinks((current) => mergeGoogleAgendaInviteeContactLinks(current, [], nextAttendees))
    }
  }

  function handleChangeSelectedAnnonce() {
    setSelectedAnnonce(null)
    setAnnonceSearch('')
    setAnnonceOptions([])
    setAnnonceError(null)
    setAnnonceLoading(false)
    setLinkedRelationContactOptions([])
    setLinkedRelationContactsError(null)
  }

  function handleAttendeesTextChange(value: string) {
    setAttendeesText(value)
    setAttendeeContactLinks((current) => mergeGoogleAgendaInviteeContactLinks(current, activeContactLink ? [activeContactLink] : [], splitEmailList(value)))
  }

  function handleRemoveGlobalAgendaInvitee(email: string) {
    const cleanEmail = normalizeEmail(email)
    const nextAttendees = attendeeEmails.filter((item) => item !== cleanEmail)
    setAttendeesText(joinEmailList(nextAttendees))
    setAttendeeContactLinks((current) => mergeGoogleAgendaInviteeContactLinks(current, [], nextAttendees))
    if (cleanEmail && cleanEmail === activeContactEmail) {
      setSelectedContact(null)
      setCreatedContactLink(null)
      setContactSearch('')
    }
  }

  function handleGlobalAgendaContactJobCreated(contact: HektorContactIdentityInput) {
    const createdEmail = hektorContactInputAgendaEmail(contact)
    const createdLabel = contactInputAgendaLabel(contact)
    if (createdEmail) {
      const link: GoogleAgendaInviteeContactLink = {
        email: createdEmail,
        label: createdLabel,
        source: 'contact_create_pending',
      }
      const nextAttendees = splitEmailList(joinEmailList([...splitEmailList(attendeesText), createdEmail]))
      setSelectedContact(null)
      setCreatedContactLink(link)
      setContactSearch(createdLabel || createdEmail)
      setContactOptions([])
      setAttendeesText(joinEmailList(nextAttendees))
      setAttendeeContactLinks((current) => mergeGoogleAgendaInviteeContactLinks(current, [link], nextAttendees))
      setMessage('Contact envoye au worker et ajoute aux invites.')
    } else {
      setMessage('Contact envoye au worker. Ajoute un email pour pouvoir inviter le client au RDV.')
    }
    setContactCreateOpen(false)
  }

  async function handleCheckAvailability() {
    setAvailabilityPending(true)
    setAvailability(null)
    setMessage(null)
    setError(null)
    try {
      const minutes = Number(durationMinutes)
      const endAt = addMinutesToDateTimeLocal(startAt, Number.isFinite(minutes) ? minutes : 60)
      if (!endAt) throw new Error('Horaire RDV invalide')
      const result = await checkGoogleCalendarAvailability({
        subjectEmail: modalCalendarEmail,
        startAt,
        endAt,
      })
      if (!result.ok) throw new Error('Verification disponibilite Google impossible')
      setAvailability(result)
    } catch (eventError) {
      setError(eventError instanceof Error ? eventError.message : 'Verification disponibilite Google impossible')
    } finally {
      setAvailabilityPending(false)
    }
  }

  async function handleSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault()
    setPending(true)
    setMessage(null)
    setError(null)
    try {
      if (isVisit && !selectedAnnonce) throw new Error('Selectionne le bien a visiter.')
      if (isVisit && !activeContactEmail) throw new Error('Selectionne le contact acquereur ou cree un contact avec email.')
      const minutes = Number(durationMinutes)
      const endAt = addMinutesToDateTimeLocal(startAt, Number.isFinite(minutes) ? minutes : 60)
      if (!endAt) throw new Error('Horaire RDV invalide')
      const attendees = splitEmailList(joinEmailList(activeContactEmail ? [...attendeeEmails, activeContactEmail] : attendeeEmails))
      const normalizedContactLinks = mergeGoogleAgendaInviteeContactLinks(attendeeContactLinks, activeContactLink ? [activeContactLink] : [], attendees)
      const attendeeContacts = googleAgendaInviteeContactMetadata(normalizedContactLinks, attendees)
      const relatedEntityType: GoogleCalendarEventLink['related_entity_type'] = selectedAnnonce ? 'annonce' : activeContactEmail ? 'contact' : 'other'
      const relationId = selectedAnnonce ? String(selectedAnnonce.app_dossier_id) : ((selectedContact?.hektor_contact_id ?? activeContactLink?.hektorContactId ?? activeContactEmail) || 'agenda_global')
      const nextMetadata = {
        source: 'agenda_global',
        contact_id: selectedContact?.hektor_contact_id ?? activeContactLink?.hektorContactId ?? null,
        contact_label: activeContactLabel || null,
        contact_email: activeContactEmail || null,
        hektor_annonce_id: selectedAnnonce?.hektor_annonce_id ?? null,
        app_dossier_id: selectedAnnonce?.app_dossier_id ?? null,
        titre_bien: selectedAnnonceTitle || null,
        numero_dossier: selectedAnnonce?.numero_dossier ?? null,
        numero_mandat: selectedAnnonce?.numero_mandat ?? null,
        ...googleAgendaAnnoncePhotoMetadata(selectedAnnonce),
        bon_visite_ready: isVisit && Boolean(selectedAnnonce) && Boolean(activeContactEmail),
        attendee_contacts: attendeeContacts,
        attendee_contact_count: attendeeContacts.length,
        ...(props.presetMetadata ?? {}),
      }
      if (editingEvent) {
        const updated = await updateGoogleCalendarEvent(editingEvent.id, {
          eventType,
          relatedEntityType,
          relatedEntityId: relationId,
          appDossierId: selectedAnnonce?.app_dossier_id ?? null,
          hektorAnnonceId: selectedAnnonce?.hektor_annonce_id ?? null,
          hektorContactId: selectedContact?.hektor_contact_id ?? activeContactLink?.hektorContactId ?? null,
          summary,
          startAt,
          endAt,
          description: description.trim() ? description : undefined,
          location,
          attendees,
          sendUpdates: 'all',
          metadata: nextMetadata,
        })
        setMessage('RDV Google modifie.')
        setAvailability(null)
        props.onUpdated?.(updated.link ?? null)
      } else {
        const created = await createGoogleCalendarEvent({
          subjectEmail: modalCalendarEmail,
          eventType,
          relatedEntityType,
          relatedEntityId: relationId,
          appDossierId: selectedAnnonce?.app_dossier_id ?? null,
          hektorAnnonceId: selectedAnnonce?.hektor_annonce_id ?? null,
          hektorContactId: selectedContact?.hektor_contact_id ?? activeContactLink?.hektorContactId ?? null,
          summary,
          startAt,
          endAt,
          description,
          location,
          attendees,
          sendUpdates: 'all',
          metadata: nextMetadata,
        })
        setMessage('RDV Google cree.')
        setAvailability(null)
        props.onCreated?.(created.link ?? null)
      }
    } catch (eventError) {
      setError(eventError instanceof Error ? eventError.message : 'Enregistrement RDV Google impossible')
    } finally {
      setPending(false)
    }
  }

  if (typeof document === 'undefined') return null

  return createPortal(
    <div className={`modal-overlay google-agenda-modal-overlay${props.overlayClassName ? ` ${props.overlayClassName}` : ''}`} onClick={props.onClose}>
      <section className="modal-panel google-agenda-modal google-agenda-contact-modal google-agenda-global-create-modal" onClick={(event) => event.stopPropagation()}>
        <div className="google-agenda-modal-head">
          <div>
            <span className="eyebrow">Agenda global</span>
            <h3>{isEditingGoogleGlobalEvent ? 'Modifier un RDV Google' : 'Creer un RDV Google'}</h3>
            <p>{formatDateTime(props.slot.start)} - {formatDateTime(props.slot.end)}</p>
          </div>
          <button className="request-modal-close" type="button" onClick={props.onClose}>Fermer</button>
        </div>
        <div className="google-agenda-modal-meta">
          <span><strong>Agenda</strong>{modalCalendarEmail || '-'}</span>
          <span><strong>Creneau</strong>{formatDateTime(props.slot.start)}</span>
          <span><strong>Libre</strong>{minutesBetweenWindow(props.slot)} min</span>
          <span><strong>Type</strong>{eventTypeLabel(eventType)}</span>
        </div>
        <div className="google-agenda-modal-layout">
          <section className="google-agenda-panel google-agenda-planner-panel">
            <div className="google-agenda-panel-head">
              <span>{isEditingGoogleGlobalEvent ? 'Modification' : 'Creation'}</span>
              <strong>{isEditingGoogleGlobalEvent ? 'Ajuster le RDV' : 'Planifier depuis l agenda'}</strong>
            </div>
            <form className="google-agenda-form" onSubmit={handleSubmit}>
              <label className="filter-field google-agenda-field-wide">
                <span>Agenda</span>
                <input value={modalCalendarEmail} type="email" disabled />
              </label>
              <label className="filter-field">
                <span>Type</span>
                <select value={eventType} onChange={(inputEvent) => setEventType(inputEvent.target.value as GoogleCalendarEventLink['event_type'])}>
                  {googleAgendaEventTypeOptions.map((option) => (
                    <option key={option.value} value={option.value}>{option.label}</option>
                  ))}
                </select>
              </label>
              {isVisit ? (
                <div className="google-agenda-field-wide google-agenda-visit-property-picker">
                  <div className="google-agenda-visit-property-head">
                    <div>
                      <span className="detail-label">Bien a visiter</span>
                      <strong>{selectedAnnonce ? selectedAnnonceTitle : 'Selectionner le bien de la visite'}</strong>
                      <small>{annonceScopeLabel}</small>
                    </div>
                    {selectedAnnonce ? (
                      <button className="ghost-button button-subtle" type="button" onClick={handleChangeSelectedAnnonce}>
                        Changer
                      </button>
                    ) : null}
                  </div>
                  {selectedAnnonce ? (
                    <div className="contact-owner-selected">
                      <strong>{selectedAnnonceTitle}</strong>
                      <span>{ownerAnnonceOptionSubtitle(selectedAnnonce) || `Annonce ${selectedAnnonce.hektor_annonce_id}`}</span>
                      <small>Ce bien servira au bon de visite.</small>
                    </div>
                  ) : (
                    <>
                      <div className="google-agenda-contact-search">
                        <input value={annonceSearch} onChange={(inputEvent) => setAnnonceSearch(inputEvent.target.value)} placeholder="Adresse, ville, dossier, mandat..." />
                      </div>
                      <small className="google-agenda-search-hint">Recherche par adresse, ville, dossier ou mandat. Saisis 3 caracteres minimum, ou un ID.</small>
                      {annonceLoading ? <p className="empty-state">Recherche biens...</p> : null}
                      {annonceError ? <p className="google-agenda-error">{annonceError}</p> : null}
                      {annonceOptions.length > 0 ? (
                        <div className="google-agenda-contact-list">
                          {annonceOptions.map((option) => (
                            <button key={`global-visit-annonce-${option.hektor_annonce_id}`} className="google-agenda-contact-button" type="button" onClick={() => handleSelectAnnonce(option)}>
                              <strong>{ownerAnnonceOptionTitle(option)}</strong>
                              <span>{ownerAnnonceOptionSubtitle(option) || `Annonce ${option.hektor_annonce_id}`}</span>
                              <small>{ownerAnnonceOptionMeta(option)}</small>
                            </button>
                          ))}
                        </div>
                      ) : annonceSearch.trim().length >= (/^\d+$/.test(annonceSearch.trim()) ? 1 : 3) && !annonceLoading ? <p className="empty-state">Aucun bien actif trouve dans le perimetre agence/negociateur.</p> : null}
                    </>
                  )}
                </div>
              ) : null}
              <label className="filter-field google-agenda-field-wide">
                <span>Titre</span>
                <input value={summary} onChange={(inputEvent) => setSummary(inputEvent.target.value)} required />
              </label>
              <label className="filter-field">
                <span>Debut</span>
                <input value={startAt} onChange={(inputEvent) => setStartAt(inputEvent.target.value)} type="datetime-local" required />
              </label>
              <label className="filter-field">
                <span>Duree</span>
                <select value={durationMinutes} onChange={(inputEvent) => setDurationMinutes(inputEvent.target.value)}>
                  {hasCustomDuration ? <option value={durationMinutes}>{durationMinutes} min</option> : null}
                  <option value="30">30 min</option>
                  <option value="45">45 min</option>
                  <option value="60">1 h</option>
                  <option value="90">1 h 30</option>
                  <option value="120">2 h</option>
                </select>
              </label>
              <label className="filter-field google-agenda-field-wide">
                <span>Lieu</span>
                <input value={location} onChange={(inputEvent) => setLocation(inputEvent.target.value)} />
              </label>
              <label className="filter-field google-agenda-field-wide">
                <span>Invites</span>
                <input value={attendeesText} onChange={(inputEvent) => handleAttendeesTextChange(inputEvent.target.value)} placeholder="client@email.fr" />
              </label>
              <div className="google-agenda-field-wide google-agenda-invitee-selected google-agenda-global-invitees">
                <span className="detail-label">Invites Google</span>
                {attendeeEmails.length > 0 ? (
                  <div className="google-agenda-invitee-chip-row">
                    {attendeeEmails.map((email) => {
                      const contactLink = attendeeContactLinks.find((item) => item.email === email) ?? (activeContactLink?.email === email ? activeContactLink : null)
                      return (
                        <button key={`global-invitee-${email}`} className={`google-agenda-invitee-chip${contactLink?.hektorContactId ? ' is-linked' : ''}`} type="button" onClick={() => handleRemoveGlobalAgendaInvitee(email)}>
                          <strong>{contactLink?.label || email}</strong>
                          <small>{contactLink?.hektorContactId ? `Contact ${contactLink.hektorContactId}` : email}</small>
                          <span aria-hidden="true">x</span>
                        </button>
                      )
                    })}
                  </div>
                ) : <p className="empty-state">Aucun invite ajoute.</p>}
              </div>
              <label className="filter-field google-agenda-field-wide">
                <span>Description</span>
                <textarea className="inline-textarea" value={description} onChange={(inputEvent) => setDescription(inputEvent.target.value)} placeholder={isEditingGoogleGlobalEvent ? 'Vide = description Google conservee' : undefined} />
              </label>
              {!canUseCalendarEmail ? <p className="google-agenda-error">Agenda Google Workspace requis.</p> : null}
              {message ? <p className="google-agenda-success">{message}</p> : null}
              {error ? <p className="google-agenda-error">{error}</p> : null}
              {availability ? (
                <div className={availability.isAvailable ? 'google-agenda-success' : 'google-agenda-warning'}>
                  <strong>{availability.isAvailable ? 'Disponible sur ce creneau.' : `Conflit agenda : ${availability.busyCount ?? availabilityBusy.length} creneau occupe.`}</strong>
                  {!availability.isAvailable && availabilityBusy.length > 0 ? (
                    <span>{availabilityBusy.slice(0, 3).map((slot) => `${formatDateTime(slot.start)} - ${formatDateTime(slot.end)}`).join(' | ')}</span>
                  ) : null}
                </div>
              ) : null}
              <div className="modal-actions google-agenda-actions">
                <button className="ghost-button button-subtle" type="button" onClick={() => void handleCheckAvailability()} disabled={availabilityPending || pending || !canUseCalendarEmail}>
                  {availabilityPending ? 'Verification...' : 'Verifier dispo'}
                </button>
                <button className="ghost-button button-primary" type="submit" disabled={pending || !canSubmit}>
                  {pending ? (isEditingGoogleGlobalEvent ? 'Enregistrement...' : 'Creation...') : isEditingGoogleGlobalEvent ? 'Enregistrer le RDV' : 'Creer RDV Google'}
                </button>
              </div>
            </form>
          </section>
          <section className="google-agenda-panel google-agenda-links-panel">
            <div className="google-agenda-panel-head">
              <span>Liaisons GTI</span>
              <strong>Contact et bien</strong>
            </div>
            <div className="google-agenda-global-link-grid">
              <div>
                <span className="detail-label">Contact</span>
                {selectedContact || createdContactLink ? (
                  <div className="contact-owner-selected">
                    <strong>{activeContactLabel || activeContactEmail}</strong>
                    <span>{activeContactEmail || selectedContact?.phone_primary || selectedContact?.phone_secondary || 'Email absent'}</span>
                    {activeContactEmail ? <small>Invite Google ajoute automatiquement.</small> : <small>Email requis pour inviter le client.</small>}
                    {createdContactLink?.source === 'contact_create_pending' ? <small>Contact en creation Hektor</small> : null}
                    <button className="ghost-button button-subtle" type="button" onClick={handleChangeSelectedContact}>Changer</button>
                  </div>
                ) : (
                  <>
                    {selectedAnnonce ? (
                      <div className="google-agenda-linked-contact-panel">
                        <span className="detail-label">Contacts du bien selectionne</span>
                        {linkedRelationContactsLoading ? <p className="empty-state">Chargement contacts lies...</p> : null}
                        {linkedRelationContactsError ? <p className="google-agenda-error">{linkedRelationContactsError}</p> : null}
                        {linkedAgendaContacts.length > 0 ? (
                          <div className="google-agenda-contact-list">
                            {linkedAgendaContacts.map((option) => {
                              const linkedOption = linkedRelationContactOptions.find((item) => String(item.hektor_contact_id) === String(option.hektorContactId))
                              return (
                                <button key={`global-linked-contact-${option.key}`} className="google-agenda-contact-button" type="button" onClick={() => linkedOption && handleSelectContact(linkedOption)} disabled={!option.link || !linkedOption}>
                                  <strong>{option.label}</strong>
                                  <span>{option.meta}</span>
                                  {option.hektorContactId ? <small>Contact {option.hektorContactId}</small> : <small>{option.email ? 'Email direct' : 'Email absent'}</small>}
                                </button>
                              )
                            })}
                          </div>
                        ) : !linkedRelationContactsLoading ? <p className="empty-state">Aucun contact lie au bien. Utilise la recherche ou cree un contact.</p> : null}
                      </div>
                    ) : null}
                    <div className="google-agenda-contact-search">
                      <input value={contactSearch} onChange={(inputEvent) => setContactSearch(inputEvent.target.value)} placeholder="Nom, email, telephone..." />
                      {props.canManageContacts ? (
                        <button className="ghost-button button-subtle" type="button" onClick={() => setContactCreateOpen(true)}>
                          Nouveau contact
                        </button>
                      ) : null}
                    </div>
                    <small className="google-agenda-search-hint">{contactScopeLabel}. Saisis 3 caracteres minimum, ou un ID contact.</small>
                    {contactSearchLoading ? <p className="empty-state">Recherche contacts...</p> : null}
                    {contactSearchError ? <p className="google-agenda-error">{contactSearchError}</p> : null}
                    {contactOptions.length > 0 ? (
                      <div className="google-agenda-contact-list">
                        {contactOptions.map((option) => {
                          const email = contactOptionAgendaEmail(option)
                          return (
                            <button key={`global-contact-${option.hektor_contact_id}`} className="google-agenda-contact-button" type="button" onClick={() => handleSelectContact(option)}>
                              <strong>{mandantContactOptionTitle(option)}</strong>
                              <span>{email || option.phone_primary || option.phone_secondary || 'Email absent'}</span>
                              <small>{mandantContactOptionSubtitle(option) || `Contact ${option.hektor_contact_id}`}</small>
                            </button>
                          )
                        })}
                      </div>
                    ) : contactSearch.trim().length >= (/^\d+$/.test(contactSearch.trim()) ? 1 : 3) && !contactSearchLoading ? <p className="empty-state">Aucun contact trouve.</p> : null}
                  </>
                )}
              </div>
              <div>
                <span className="detail-label">{isVisit ? 'Bien a visiter' : 'Bien lie facultatif'}</span>
                {selectedAnnonce ? (
                  <div className="contact-owner-selected">
                    <strong>{selectedAnnonceTitle}</strong>
                    <span>{ownerAnnonceOptionSubtitle(selectedAnnonce) || `Annonce ${selectedAnnonce.hektor_annonce_id}`}</span>
                    {isVisit ? <small>Ce bien servira au bon de visite.</small> : <small>RDV lie a cette annonce.</small>}
                    <button className="ghost-button button-subtle" type="button" onClick={handleChangeSelectedAnnonce}>Changer</button>
                  </div>
                ) : (
                  isVisit ? (
                    <p className="empty-state">Choisis le bien dans le bloc visible du formulaire de creation. Le bouton de creation restera bloque tant que le bien n'est pas selectionne.</p>
                  ) : (
                  <>
                    <div className="google-agenda-contact-search">
                      <input value={annonceSearch} onChange={(inputEvent) => setAnnonceSearch(inputEvent.target.value)} placeholder="Adresse, ville, dossier, mandat..." />
                    </div>
                    <small className="google-agenda-search-hint">{annonceScopeLabel}. Recherche par adresse, ville, dossier ou mandat.</small>
                    {annonceLoading ? <p className="empty-state">Recherche biens...</p> : null}
                    {annonceError ? <p className="google-agenda-error">{annonceError}</p> : null}
                    {annonceOptions.length > 0 ? (
                      <div className="google-agenda-contact-list">
                        {annonceOptions.map((option) => (
                          <button key={`global-annonce-${option.hektor_annonce_id}`} className="google-agenda-contact-button" type="button" onClick={() => handleSelectAnnonce(option)}>
                            <strong>{ownerAnnonceOptionTitle(option)}</strong>
                            <span>{ownerAnnonceOptionSubtitle(option) || `Annonce ${option.hektor_annonce_id}`}</span>
                            <small>{ownerAnnonceOptionMeta(option)}</small>
                          </button>
                        ))}
                      </div>
                    ) : annonceSearch.trim().length >= (/^\d+$/.test(annonceSearch.trim()) ? 1 : 3) && !annonceLoading ? <p className="empty-state">Aucun bien actif trouve.</p> : null}
                  </>
                  )
                )}
              </div>
            </div>
            <div className="info-grid google-agenda-global-summary">
              <InfoCard label="Contact" value={activeContactLabel || '-'} />
              <InfoCard label="Bien" value={selectedAnnonceTitle || '-'} />
              <InfoCard label="Mandat" value={selectedAnnonce?.numero_mandat || '-'} />
              <InfoCard label="Dossier" value={selectedAnnonce?.numero_dossier || '-'} />
            </div>
            {isVisit && (!selectedAnnonce || !activeContactEmail) ? <p className="google-agenda-warning">Pour une visite, le contact avec email et le bien sont obligatoires.</p> : null}
          </section>
        </div>
        {contactCreateOpen && props.canManageContacts ? (
          <ContactWorkflowModal
            title="Nouveau contact"
            eyebrow="Creation Hektor"
            summary="Creation via le workflow contact existant, puis ajout aux invites si un email est renseigne."
            tone="create"
            onClose={() => setContactCreateOpen(false)}
          >
            <HektorContactIdentityForm
              mode="create"
              hektorUserEmail={defaultContactHektorUserEmail}
              hektorUserId={defaultContactHektorUserId}
              hektorNegotiators={props.hektorNegotiators}
              profileRole={props.profileRole}
              sessionEmail={props.sessionEmail}
              onCancel={() => setContactCreateOpen(false)}
              onJobCreated={props.onHektorActionJobCreated}
              onContactInputCreated={handleGlobalAgendaContactJobCreated}
            />
          </ContactWorkflowModal>
        ) : null}
      </section>
    </div>,
    document.body,
  )
}

function DossierPropositionsSection({ dossier, onOpenContact }: { dossier: Dossier | null; onOpenContact?: (contactId: string) => void }) {
  const [rows, setRows] = useState<DossierPropositionRow[]>([])
  const [loading, setLoading] = useState(false)
  const dossierId = dossier?.app_dossier_id ?? null
  useEffect(() => {
    if (dossierId == null) { setRows([]); return }
    let cancelled = false
    setLoading(true)
    loadDossierPropositions(dossierId)
      .then((r) => { if (!cancelled) setRows(r) })
      .catch(() => { if (!cancelled) setRows([]) })
      .finally(() => { if (!cancelled) setLoading(false) })
    return () => { cancelled = true }
  }, [dossierId])

  const channelLabel = (c: string) => (
    c === 'email' ? 'Email' : c === 'telephone' ? 'Téléphone'
      : c === 'visite' ? 'Visite (sur place)' : c === 'virtuelle' ? 'Visite (à distance)'
      : c === 'rdv' ? 'Visite du bien' : c
  )
  const fmtDate = (d: string) => { try { return new Date(d).toLocaleDateString('fr-FR', { day: '2-digit', month: '2-digit', year: 'numeric' }) } catch { return d } }
  const propName = (r: DossierPropositionRow) => r.display_name || [r.civilite, r.prenom, r.nom].filter(Boolean).join(' ') || r.hektor_contact_id

  return (
    <section className="detail-card dossier-prop-section">
      <div className="detail-card-head"><h3>Propositions acquéreurs</h3>{rows.length > 0 ? <span className="dossier-prop-count">{rows.length}</span> : null}</div>
      {loading ? (
        <p className="empty-state">Chargement…</p>
      ) : rows.length === 0 ? (
        <p className="empty-state">Ce bien n'a été proposé à aucun acquéreur depuis le rapprochement.</p>
      ) : (
        <div className="dossier-prop-list">
          {rows.map((r, i) => (
            <div key={`${r.hektor_contact_id}-${i}`} className="dossier-prop-row">
              <button type="button" className="dpr-name" onClick={() => r.hektor_contact_id && onOpenContact?.(r.hektor_contact_id)} title="Ouvrir la fiche contact">
                <strong>{propName(r)}</strong>
                <small>{channelLabel(r.channel)} · {fmtDate(r.created_at)}{r.status_after === 'visite' ? ' · Visite prévue' : ''}</small>
              </button>
              {r.gmail_thread_id ? (
                <a className="dpr-mail" href={`https://mail.google.com/mail/u/0/#all/${r.gmail_thread_id}`} target="_blank" rel="noreferrer">Voir l'email →</a>
              ) : null}
            </div>
          ))}
        </div>
      )}
    </section>
  )
}

function GoogleAgendaAnnonceSection(props: {
  dossier: Dossier | null
  detail: DossierDetailPayload
  contacts: DetailContact[]
  canManageContacts?: boolean
  hektorUserEmail?: string | null
  hektorUserId?: string | null
  hektorNegotiators?: HektorNegotiatorOption[]
  profileRole?: UserProfile['role'] | null
  sessionEmail?: string | null
  onOpenContact?: (contactId: string) => void
  onHektorActionJobCreated?: (job: ConsoleJob) => void
}) {
  const dossier = props.dossier
  const appDossierId = dossier?.app_dossier_id ?? null
  const hektorAnnonceId = dossier?.hektor_annonce_id ?? null
  const defaultCalendarEmail = resolveGoogleWorkspaceCalendarEmail({
    emails: [props.detail.appointment_negociateur_email, dossier?.negociateur_email],
    commercialId: props.detail.appointment_negociateur_id ?? dossier?.commercial_id,
    label: dossier?.commercial_nom,
    hektorNegotiators: props.hektorNegotiators,
  })
  const defaultLocation = [
    safeText(props.detail.adresse_privee_listing) || safeText(props.detail.adresse_detail),
    safeText(props.detail.code_postal_public_listing) || safeText(props.detail.code_postal_detail) || safeText(dossier?.code_postal),
    safeText(props.detail.ville_publique_listing) || safeText(props.detail.ville_privee_detail) || safeText(dossier?.ville),
  ].filter(Boolean).join(' ')
  const [calendarEmail, setCalendarEmail] = useState(defaultCalendarEmail)
  const [eventType, setEventType] = useState<GoogleCalendarEventLink['event_type']>('visite')
  const [summary, setSummary] = useState('')
  const [startAt, setStartAt] = useState(defaultGoogleAgendaStartValue)
  const [durationMinutes, setDurationMinutes] = useState('60')
  const [location, setLocation] = useState(defaultLocation)
  const [attendeesText, setAttendeesText] = useState('')
  const [attendeeContactLinks, setAttendeeContactLinks] = useState<GoogleAgendaInviteeContactLink[]>([])
  const [description, setDescription] = useState('')
  const [events, setEvents] = useState<GoogleCalendarEventLink[]>([])
  const [modalOpen, setModalOpen] = useState(false)
  const [agendaDate, setAgendaDate] = useState(dateInputFromDateTimeLocal(defaultGoogleAgendaStartValue()))
  const [agendaMode, setAgendaMode] = useState<GoogleAgendaViewMode>('day')
  const [dayAvailabilityPending, setDayAvailabilityPending] = useState(false)
  const [dayAvailability, setDayAvailability] = useState<GoogleCalendarAvailability | null>(null)
  const [periodLinkedEvents, setPeriodLinkedEvents] = useState<GoogleCalendarEventLink[]>([])
  const [contactSearch, setContactSearch] = useState('')
  const [contactOptions, setContactOptions] = useState<MandantContactSearchOption[]>([])
  const [contactSearchLoading, setContactSearchLoading] = useState(false)
  const [contactSearchError, setContactSearchError] = useState<string | null>(null)
  const [linkedRelationContactOptions, setLinkedRelationContactOptions] = useState<AnnonceContactInviteeOption[]>([])
  const [linkedRelationContactsLoading, setLinkedRelationContactsLoading] = useState(false)
  const [linkedRelationContactsError, setLinkedRelationContactsError] = useState<string | null>(null)
  const [contactCreateOpen, setContactCreateOpen] = useState(false)
  const [loading, setLoading] = useState(false)
  const [pending, setPending] = useState(false)
  const [availabilityPending, setAvailabilityPending] = useState(false)
  const [availability, setAvailability] = useState<GoogleCalendarAvailability | null>(null)
  const [editingEventId, setEditingEventId] = useState<string | null>(null)
  const [deletingId, setDeletingId] = useState<string | null>(null)
  const [printingId, setPrintingId] = useState<string | null>(null)
  const [message, setMessage] = useState<string | null>(null)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    if (editingEventId) return
    setCalendarEmail(defaultCalendarEmail)
  }, [defaultCalendarEmail, editingEventId])

  useEffect(() => {
    if (editingEventId) return
    setLocation(defaultLocation)
  }, [defaultLocation, editingEventId])

  useEffect(() => {
    if (editingEventId) return
    const title = dossier?.titre_bien || dossier?.numero_dossier || (dossier?.hektor_annonce_id ? `Annonce ${dossier.hektor_annonce_id}` : 'Annonce GTI')
    const label = googleAgendaEventTypeOptions.find((option) => option.value === eventType)?.label ?? 'RDV'
    setSummary(`${label} GTI - ${title}`)
  }, [dossier?.hektor_annonce_id, dossier?.numero_dossier, dossier?.titre_bien, editingEventId, eventType])

  useEffect(() => {
    if (editingEventId) return
    const title = dossier?.titre_bien || dossier?.numero_dossier || `Annonce ${dossier?.hektor_annonce_id ?? ''}`.trim()
    setDescription([
      'RDV cree depuis GTI.',
      title ? `Bien : ${title}` : '',
      dossier?.hektor_annonce_id ? `Annonce Hektor : ${dossier.hektor_annonce_id}` : '',
      dossier?.numero_dossier ? `Dossier : ${dossier.numero_dossier}` : '',
      dossier?.numero_mandat ? `Mandat : ${dossier.numero_mandat}` : '',
    ].filter(Boolean).join('\n'))
  }, [dossier?.hektor_annonce_id, dossier?.numero_dossier, dossier?.numero_mandat, dossier?.titre_bien, editingEventId])

  useEffect(() => {
    setEditingEventId(null)
  }, [appDossierId, hektorAnnonceId])

  useEffect(() => {
    setAvailability(null)
  }, [calendarEmail, durationMinutes, startAt])

  useEffect(() => {
    setAgendaDate(dateInputFromDateTimeLocal(startAt))
  }, [startAt])

  useEffect(() => {
    setDayAvailability(null)
    setPeriodLinkedEvents([])
  }, [agendaMode, calendarEmail])

  useEffect(() => {
    if (!modalOpen) return
    const search = contactSearch.trim()
    const scopedCalendarEmail = calendarEmail.trim().toLowerCase()
    const hektorContactSearchOwner = findContactHektorOption(props.hektorNegotiators ?? [], {
      idUser: dossier?.commercial_id,
      email: dossier?.negociateur_email || scopedCalendarEmail,
    })
    const contactSearchNegotiatorEmail = normalizeEmail(hektorContactSearchOwner?.email)
      || normalizeEmail(dossier?.negociateur_email)
      || scopedCalendarEmail
    const contactSearchAgencyName = (hektorContactSearchOwner?.agenceNom || dossier?.agence_nom || '').trim()
    const contactScope = contactSearchAgencyName
      ? { agencyName: contactSearchAgencyName, negotiatorEmail: contactSearchNegotiatorEmail || null }
      : contactSearchNegotiatorEmail.endsWith(`@${googleWorkspaceDomain}`)
        ? { negotiatorEmail: contactSearchNegotiatorEmail }
        : null
    const minSearchLength = /^\d+$/.test(search) ? 1 : 3
    if (search.length < minSearchLength) {
      setContactOptions([])
      setContactSearchLoading(false)
      setContactSearchError(null)
      return
    }
    let cancelled = false
    setContactSearchLoading(true)
    setContactSearchError(null)
    const handle = window.setTimeout(async () => {
      try {
        const rows = await searchMandantContactOptions({ search, scope: contactScope, limit: 8 })
        if (cancelled) return
        setContactOptions(rows)
      } catch (searchError) {
        if (cancelled) return
        setContactOptions([])
        setContactSearchError(searchError instanceof Error ? searchError.message : 'Recherche contact impossible.')
      } finally {
        if (!cancelled) setContactSearchLoading(false)
      }
    }, 260)
    return () => {
      cancelled = true
      window.clearTimeout(handle)
    }
  }, [calendarEmail, contactSearch, dossier?.agence_nom, dossier?.commercial_id, dossier?.negociateur_email, modalOpen, props.hektorNegotiators])

  useEffect(() => {
    if (!modalOpen || (!appDossierId && !hektorAnnonceId)) {
      setLinkedRelationContactOptions([])
      setLinkedRelationContactsLoading(false)
      setLinkedRelationContactsError(null)
      return
    }
    let cancelled = false
    setLinkedRelationContactsLoading(true)
    setLinkedRelationContactsError(null)
    void loadAnnonceContactInvitees({ appDossierId, hektorAnnonceId, limit: 24 })
      .then((rows) => {
        if (!cancelled) setLinkedRelationContactOptions(rows)
      })
      .catch((relationError) => {
        if (cancelled) return
        setLinkedRelationContactOptions([])
        setLinkedRelationContactsError(relationError instanceof Error ? relationError.message : 'Contacts lies impossibles a charger.')
      })
      .finally(() => {
        if (!cancelled) setLinkedRelationContactsLoading(false)
      })
    return () => {
      cancelled = true
    }
  }, [appDossierId, hektorAnnonceId, modalOpen])

  const canUseCalendarEmail = calendarEmail.trim().toLowerCase().endsWith(`@${googleWorkspaceDomain}`)
  const isVisit = eventType === 'visite'
  const activeEvents = events.filter((item) => item.status !== 'deleted')
  const attendeeEmails = splitEmailList(attendeesText)
  const canSubmitGoogleAgendaEvent = Boolean(summary.trim()) && (!isVisit || attendeeEmails.length > 0)
  const linkedAgendaContacts = useMemo(() => {
    const contactsByKey = new Map<string, GoogleAgendaLinkedInviteeOption>()
    const addContact = (item: Omit<GoogleAgendaLinkedInviteeOption, 'key'>) => {
      const hektorContactId = safeText(item.hektorContactId)
      const email = safeText(item.email).toLowerCase()
      const key = hektorContactId ? `contact-${hektorContactId}` : email ? `email-${email}` : `label-${item.label}-${contactsByKey.size}`
      const link = item.link ?? (email ? {
        email,
        label: item.label,
        hektorContactId: hektorContactId || null,
        source: 'annonce_contact',
      } : null)
      const next = { ...item, key, email, hektorContactId: hektorContactId || null, link }
      const existing = contactsByKey.get(key)
      if (!existing || (!existing.email && next.email)) contactsByKey.set(key, next)
    }

    props.contacts.forEach((contact) => {
      const email = detailContactAgendaEmail(contact)
      const contactId = detailContactDirectoryId(contact)
      addContact({
        label: detailContactAgendaLabel(contact),
        email,
        meta: email || contact.phone || 'Email absent',
        hektorContactId: contactId,
        link: detailContactAgendaLink(contact, email),
      })
    })

    linkedRelationContactOptions.forEach((option) => {
      const email = contactOptionAgendaEmail(option)
      const relationLabel = googleAgendaRelationRoleLabel(option.role_contact)
      const secondary = email || option.phone_primary || option.phone_secondary || 'Email absent'
      addContact({
        label: mandantContactOptionTitle(option),
        email,
        meta: `${relationLabel} - ${secondary}`,
        hektorContactId: option.hektor_contact_id,
        link: contactOptionAgendaLink(option, email),
      })
    })

    return Array.from(contactsByKey.values())
  }, [linkedRelationContactOptions, props.contacts])
  const isEditingGoogleAgendaEvent = Boolean(editingEventId)
  const hasCustomDuration = durationMinutes && !googleAgendaDurationOptions.includes(durationMinutes)
  const availabilityBusy = availability?.busy ?? []
  const canCheckAvailability = canUseCalendarEmail && Boolean(startAt) && Boolean(durationMinutes)
  const agendaPeriodDays = googleAgendaPeriodDays(agendaDate, agendaMode)
  const periodEvents = mergeGoogleCalendarEventLinks([...periodLinkedEvents, ...activeEvents])
  const agendaDayPlans = agendaPeriodDays.map((day) => ({
    day,
    label: googleAgendaDayLabel(day),
    events: googleAgendaEventsForDay(periodEvents, day),
    ...buildGoogleAgendaDayWindows(day, dayAvailability),
  }))
  const requestedDurationMinutes = Number(durationMinutes)
  const suggestedWindows = buildGoogleAgendaSuggestedWindows(agendaDayPlans.flatMap((day) => day.free), requestedDurationMinutes, 5)
  const nextLinkedEvent = activeEvents
    .filter((item) => new Date(item.starts_at).getTime() >= Date.now())
    .sort((left, right) => new Date(left.starts_at).getTime() - new Date(right.starts_at).getTime())[0]

  const reloadEvents = useCallback(async () => {
    if (!appDossierId && !hektorAnnonceId) return
    setLoading(true)
    setError(null)
    try {
      const rows = await loadGoogleCalendarEventLinks({
        appDossierId,
        hektorAnnonceId,
        limit: 25,
      })
      setEvents(rows)
    } catch (eventError) {
      setError(eventError instanceof Error ? eventError.message : 'Chargement Agenda Google impossible')
    } finally {
      setLoading(false)
    }
  }, [appDossierId, hektorAnnonceId])

  useEffect(() => {
    void reloadEvents()
  }, [reloadEvents])

  function resetGoogleAgendaForm() {
    setEditingEventId(null)
    setEventType('visite')
    setStartAt(defaultGoogleAgendaStartValue())
    setDurationMinutes('60')
    setLocation(defaultLocation)
    setAttendeesText('')
    setAttendeeContactLinks([])
    setDescription('')
    setAvailability(null)
  }

  function handleEditGoogleAgendaEvent(link: GoogleCalendarEventLink) {
    const nextStartAt = toExistingDateTimeLocalValue(link.starts_at, defaultGoogleAgendaStartValue())
    setEditingEventId(link.id)
    setCalendarEmail(link.google_calendar_email)
    setEventType(link.event_type)
    setSummary(link.summary)
    setStartAt(nextStartAt)
    setDurationMinutes(minutesBetweenDateTimes(link.starts_at, link.ends_at))
    setLocation(link.location ?? '')
    const nextAttendees = Array.isArray(link.attendees_json) ? link.attendees_json : []
    setAttendeesText(nextAttendees.join(', '))
    setAttendeeContactLinks(mergeGoogleAgendaInviteeContactLinks([], googleAgendaEventInviteeContacts(link), nextAttendees))
    setDescription('')
    setAvailability(null)
    setMessage(null)
    setError(null)
  }

  async function handleCheckGoogleAgendaAvailability() {
    setAvailabilityPending(true)
    setAvailability(null)
    setMessage(null)
    setError(null)
    try {
      const minutes = Number(durationMinutes)
      const endAt = addMinutesToDateTimeLocal(startAt, Number.isFinite(minutes) ? minutes : 60)
      if (!endAt) throw new Error('Horaire RDV invalide')
      const result = await checkGoogleCalendarAvailability({
        subjectEmail: calendarEmail,
        startAt,
        endAt,
      })
      if (!result.ok) throw new Error('Verification disponibilite Google impossible')
      setAvailability(result)
    } catch (eventError) {
      setError(eventError instanceof Error ? eventError.message : 'Verification disponibilite Google impossible')
    } finally {
      setAvailabilityPending(false)
    }
  }

  async function handleLoadGoogleAgendaPeriod(dayValue = agendaDate, mode = agendaMode) {
    setDayAvailabilityPending(true)
    setDayAvailability(null)
    setPeriodLinkedEvents([])
    setError(null)
    try {
      if (!canUseCalendarEmail) throw new Error('Agenda Google Workspace requis')
      const range = googleAgendaPeriodRange(dayValue, mode)
      const result = await checkGoogleCalendarAvailability({
        subjectEmail: calendarEmail,
        startAt: range.startAt,
        endAt: range.endAt,
      })
      if (!result.ok) throw new Error('Chargement occupation agenda impossible')
      setDayAvailability(result)
      try {
        const rows = await loadGoogleCalendarEventLinks({
          calendarEmail,
          startAt: range.startAt,
          endAt: range.endAt,
          limit: 100,
        })
        setPeriodLinkedEvents(rows)
      } catch {
        setPeriodLinkedEvents([])
      }
    } catch (eventError) {
      setError(eventError instanceof Error ? eventError.message : 'Chargement occupation agenda impossible')
    } finally {
      setDayAvailabilityPending(false)
    }
  }

  function handleOpenGoogleAgendaModal() {
    const nextDate = dateInputFromDateTimeLocal(startAt)
    setAgendaDate(nextDate)
    setModalOpen(true)
    void reloadEvents()
    if (canUseCalendarEmail) {
      void handleLoadGoogleAgendaPeriod(nextDate, agendaMode)
    }
  }

  function handleCloseGoogleAgendaModal() {
    setModalOpen(false)
  }

  function handleUseGoogleAgendaWindow(window: GoogleAgendaWindow) {
    const windowMinutes = minutesBetweenWindow(window)
    const requestedMinutes = Number(durationMinutes)
    setStartAt(toDateTimeLocalValue(new Date(window.start)))
    if (Number.isFinite(requestedMinutes) && requestedMinutes > windowMinutes) {
      setDurationMinutes(String(windowMinutes))
    }
    setAvailability(null)
  }

  function handleAttendeesTextChange(value: string) {
    setAttendeesText(value)
    setAttendeeContactLinks((current) => mergeGoogleAgendaInviteeContactLinks(current, [], splitEmailList(value)))
  }

  function handleAddAgendaInvitee(link: GoogleAgendaInviteeContactLink | string) {
    const normalized = typeof link === 'string'
      ? normalizeGoogleAgendaInviteeContactLink({ email: link })
      : normalizeGoogleAgendaInviteeContactLink(link)
    if (!normalized) return
    const nextText = joinEmailList([...splitEmailList(attendeesText), normalized.email])
    const nextAttendees = splitEmailList(nextText)
    setAttendeesText(nextText)
    setAttendeeContactLinks((current) => mergeGoogleAgendaInviteeContactLinks(current, [normalized], nextAttendees))
  }

  function handleRemoveAgendaInvitee(email: string) {
    const cleanEmail = email.trim().toLowerCase()
    const nextText = joinEmailList(splitEmailList(attendeesText).filter((item) => item !== cleanEmail))
    const nextAttendees = splitEmailList(nextText)
    setAttendeesText(nextText)
    setAttendeeContactLinks((current) => mergeGoogleAgendaInviteeContactLinks(current, [], nextAttendees))
  }

  function handleGoogleAgendaContactJobCreated(contact: HektorContactIdentityInput) {
    const createdEmail = hektorContactInputAgendaEmail(contact)
    if (createdEmail) {
      handleAddAgendaInvitee({
        email: createdEmail,
        label: contactInputAgendaLabel(contact),
        source: 'contact_create_pending',
      })
    }
    setContactCreateOpen(false)
    setMessage(createdEmail ? 'Contact envoye au worker et ajoute aux invites.' : 'Contact envoye au worker.')
  }

  async function handleSubmitGoogleAgendaEvent(event: FormEvent<HTMLFormElement>) {
    event.preventDefault()
    if (!dossier) return
    setPending(true)
    setMessage(null)
    setError(null)
    try {
      const minutes = Number(durationMinutes)
      const endAt = addMinutesToDateTimeLocal(startAt, Number.isFinite(minutes) ? minutes : 60)
      if (!endAt) throw new Error('Horaire RDV invalide')
      const attendees = attendeeEmails
      const attendeeContacts = googleAgendaInviteeContactMetadata(attendeeContactLinks, attendees)
      const primaryHektorContactId = attendeeContacts
        .map((item) => safeText(item.hektor_contact_id))
        .find(Boolean) ?? null
      if (isVisit && attendees.length === 0) throw new Error('Ajoute au moins un contact invite pour preparer le bon de visite.')
      const bonVisiteReady = isVisit && attendees.length > 0
      if (editingEventId) {
        await updateGoogleCalendarEvent(editingEventId, {
          summary,
          startAt,
          endAt,
          description: description.trim() ? description : undefined,
          location,
          attendees,
          hektorContactId: primaryHektorContactId,
          metadata: {
            source: 'fiche_annonce',
            hektor_annonce_id: dossier.hektor_annonce_id,
            app_dossier_id: dossier.app_dossier_id,
            titre_bien: dossier.titre_bien,
            numero_dossier: dossier.numero_dossier,
            numero_mandat: dossier.numero_mandat,
            ...googleAgendaAnnoncePhotoMetadata(dossier),
            bon_visite_ready: bonVisiteReady,
            attendee_contacts: attendeeContacts,
            attendee_contact_count: attendeeContacts.length,
          },
          sendUpdates: 'all',
        })
        resetGoogleAgendaForm()
        setMessage('RDV Google modifie.')
      } else {
        await createGoogleCalendarEvent({
          subjectEmail: calendarEmail,
          eventType,
          relatedEntityType: 'annonce',
          relatedEntityId: String(dossier.app_dossier_id),
          appDossierId: dossier.app_dossier_id,
          hektorAnnonceId: dossier.hektor_annonce_id,
          hektorContactId: primaryHektorContactId,
          summary,
          startAt,
          endAt,
          description,
          location,
          attendees,
          sendUpdates: 'all',
          metadata: {
            source: 'fiche_annonce',
            hektor_annonce_id: dossier.hektor_annonce_id,
            app_dossier_id: dossier.app_dossier_id,
            titre_bien: dossier.titre_bien,
            numero_dossier: dossier.numero_dossier,
            numero_mandat: dossier.numero_mandat,
            ...googleAgendaAnnoncePhotoMetadata(dossier),
            bon_visite_ready: bonVisiteReady,
            attendee_contacts: attendeeContacts,
            attendee_contact_count: attendeeContacts.length,
          },
        })
        setMessage('RDV Google cree.')
        setAttendeesText('')
        setAttendeeContactLinks([])
      }
      setAvailability(null)
      await reloadEvents()
    } catch (eventError) {
      setError(eventError instanceof Error ? eventError.message : 'Enregistrement RDV Google impossible')
    } finally {
      setPending(false)
    }
  }

  async function handleDeleteGoogleAgendaEvent(link: GoogleCalendarEventLink) {
    if (!window.confirm(`Supprimer ce RDV Google : ${link.summary} ?`)) return
    setDeletingId(link.id)
    setMessage(null)
    setError(null)
    try {
      await deleteGoogleCalendarEvent(link.id, { sendUpdates: 'all' })
      setMessage('RDV Google supprime.')
      await reloadEvents()
    } catch (eventError) {
      setError(eventError instanceof Error ? eventError.message : 'Suppression RDV Google impossible')
    } finally {
      setDeletingId(null)
    }
  }

  async function handlePrintGoogleAgendaVisitVoucher(link: GoogleCalendarEventLink) {
    if (!dossier) return
    const voucherContact = visitVoucherContactFromAnnonceEvent(link, props.contacts)
    const voucherRelations = visitVoucherRelationsFromDossier(dossier)
    const printWindow = window.open('', '_blank')
    writeVisitVoucherWindow(printWindow, visitVoucherLoadingHtml())
    setPrintingId(link.id)
    setMessage(null)
    setError(null)
    let photoUrl: string | null = null
    try {
      photoUrl = await loadVisitVoucherPhotoUrl(link, voucherRelations)
    } catch (photoError) {
      console.warn('Visit voucher photo loading failed', photoError)
    } finally {
      openVisitVoucherPrint(voucherContact, link, voucherRelations, photoUrl, printWindow)
      setPrintingId(null)
    }
  }

  return (
    <section className="detail-section detail-google-agenda-section">
      <div className="section-header">
        <DetailSectionTitle icon="commercial" title="Agenda Google" />
        {loading ? <span>Chargement...</span> : null}
      </div>
      <article className="detail-card google-agenda-entry-card">
        <div>
          <span className="detail-label">Rendez-vous Google</span>
          <div className="info-grid">
            <InfoCard label="Agenda" value={calendarEmail || '-'} />
            <InfoCard label="RDV lies" value={String(activeEvents.length)} />
            <InfoCard label="Prochain RDV" value={nextLinkedEvent ? formatDateTime(nextLinkedEvent.starts_at) : '-'} />
          </div>
        </div>
        <div className="google-agenda-entry-actions">
          {!canUseCalendarEmail ? <p className="google-agenda-error">Agenda Google Workspace requis.</p> : null}
          <button className="ghost-button button-primary" type="button" onClick={handleOpenGoogleAgendaModal}>
            Ouvrir les RDV Google
          </button>
        </div>
      </article>
      {modalOpen && typeof document !== 'undefined' ? createPortal(
        <div className="modal-overlay google-agenda-modal-overlay" onClick={handleCloseGoogleAgendaModal}>
          <section className="modal-panel google-agenda-modal" onClick={(event) => event.stopPropagation()}>
            <div className="google-agenda-modal-head">
              <div>
                <span className="eyebrow">Google Agenda</span>
                <h3>Rendez-vous Google</h3>
                <p>{dossier?.titre_bien || dossier?.numero_dossier || 'Annonce GTI'}</p>
              </div>
              <button className="request-modal-close" type="button" onClick={handleCloseGoogleAgendaModal}>Fermer</button>
            </div>
            <div className="google-agenda-modal-meta">
              <span><strong>Agenda</strong>{calendarEmail || '-'}</span>
              <span><strong>Commercial</strong>{dossier?.commercial_nom || '-'}</span>
              <span><strong>Mandat</strong>{dossier?.numero_mandat || '-'}</span>
              <span><strong>RDV lies</strong>{activeEvents.length}</span>
            </div>
            <div className="google-agenda-modal-layout">
              <section className="google-agenda-panel google-agenda-planner-panel">
                <div className="google-agenda-panel-head">
                  <span>{isEditingGoogleAgendaEvent ? 'Modification' : 'Creation'}</span>
                  <strong>{isEditingGoogleAgendaEvent ? 'Modifier le RDV' : 'Planifier un RDV'}</strong>
                </div>
                <form className="google-agenda-form" onSubmit={handleSubmitGoogleAgendaEvent}>
                  <label className="filter-field google-agenda-field-wide">
                    <span>Agenda</span>
                    <input value={calendarEmail} onChange={(inputEvent) => setCalendarEmail(inputEvent.target.value)} type="email" placeholder={`nego@${googleWorkspaceDomain}`} required disabled={isEditingGoogleAgendaEvent} />
                  </label>
                  <label className="filter-field">
                    <span>Type</span>
                    <select value={eventType} onChange={(inputEvent) => setEventType(inputEvent.target.value as GoogleCalendarEventLink['event_type'])}>
                      {googleAgendaEventTypeOptions.map((option) => (
                        <option key={option.value} value={option.value}>{option.label}</option>
                      ))}
                    </select>
                  </label>
                  <label className="filter-field google-agenda-field-wide">
                    <span>Titre</span>
                    <input value={summary} onChange={(inputEvent) => setSummary(inputEvent.target.value)} required />
                  </label>
                  <label className="filter-field">
                    <span>Debut</span>
                    <input value={startAt} onChange={(inputEvent) => setStartAt(inputEvent.target.value)} type="datetime-local" required />
                  </label>
                  <label className="filter-field">
                    <span>Duree</span>
                    <select value={durationMinutes} onChange={(inputEvent) => setDurationMinutes(inputEvent.target.value)}>
                      {hasCustomDuration ? <option value={durationMinutes}>{durationMinutes} min</option> : null}
                      <option value="30">30 min</option>
                      <option value="45">45 min</option>
                      <option value="60">1 h</option>
                      <option value="90">1 h 30</option>
                      <option value="120">2 h</option>
                    </select>
                  </label>
                  <label className="filter-field google-agenda-field-wide">
                    <span>Lieu</span>
                    <input value={location} onChange={(inputEvent) => setLocation(inputEvent.target.value)} />
                  </label>
                  <label className="filter-field google-agenda-field-wide">
                    <span>Invites</span>
                    <input value={attendeesText} onChange={(inputEvent) => handleAttendeesTextChange(inputEvent.target.value)} placeholder="client@email.fr" />
                  </label>
                  {isVisit && attendeeEmails.length === 0 ? (
                    <p className="google-agenda-warning">Pour une visite, ajoute au moins un contact invite afin de preparer le bon de visite.</p>
                  ) : null}
                  <div className="google-agenda-field-wide google-agenda-invitees">
                    <div className="google-agenda-invitee-selected">
                      <span className="detail-label">Invites selectionnes</span>
                      {attendeeEmails.length > 0 ? (
                        <div className="google-agenda-invitee-chip-row">
                          {attendeeEmails.map((email) => {
                            const contactLink = attendeeContactLinks.find((item) => item.email === email)
                            return (
                              <button key={`invitee-${email}`} className={`google-agenda-invitee-chip${contactLink?.hektorContactId ? ' is-linked' : ''}`} type="button" onClick={() => handleRemoveAgendaInvitee(email)}>
                                <strong>{contactLink?.label || email}</strong>
                                <small>{contactLink?.hektorContactId ? `Contact ${contactLink.hektorContactId}` : email}</small>
                                <span aria-hidden="true">x</span>
                              </button>
                            )
                          })}
                        </div>
                      ) : <p className="empty-state">Aucun invite ajoute.</p>}
                    </div>
                    <div className="google-agenda-invitee-tools">
                      <div>
                        <span className="detail-label">Contacts lies a l'annonce</span>
                        {linkedRelationContactsLoading ? <p className="empty-state">Chargement contacts lies...</p> : null}
                        {linkedRelationContactsError ? <p className="google-agenda-error">{linkedRelationContactsError}</p> : null}
                        {linkedAgendaContacts.length > 0 ? (
                          <div className="google-agenda-contact-list">
                            {linkedAgendaContacts.map((option) => {
                              return (
                                <button key={`linked-contact-${option.key}`} className="google-agenda-contact-button" type="button" onClick={() => option.link && handleAddAgendaInvitee(option.link)} disabled={!option.link}>
                                  <strong>{option.label}</strong>
                                  <span>{option.meta}</span>
                                  {option.hektorContactId ? <small>Contact {option.hektorContactId}</small> : <small>{option.email ? 'Email direct' : 'Email absent'}</small>}
                                </button>
                              )
                            })}
                          </div>
                        ) : !linkedRelationContactsLoading ? <p className="empty-state">Aucun contact lie trouve.</p> : null}
                      </div>
                      <div>
                        <span className="detail-label">Recherche etendue</span>
                        <div className="google-agenda-contact-search">
                          <input value={contactSearch} onChange={(inputEvent) => setContactSearch(inputEvent.target.value)} placeholder="Nom, email, telephone..." />
                          {props.canManageContacts ? (
                            <button className="ghost-button button-subtle" type="button" onClick={() => setContactCreateOpen(true)}>
                              Nouveau contact
                            </button>
                          ) : null}
                        </div>
                        {contactSearchLoading ? <p className="empty-state">Recherche contacts...</p> : null}
                        {contactSearchError ? <p className="google-agenda-error">{contactSearchError}</p> : null}
                        {contactSearch.trim().length > 0 && contactSearch.trim().length < (/^\d+$/.test(contactSearch.trim()) ? 1 : 3) ? <p className="empty-state">Saisis au moins 3 caracteres pour lancer la recherche.</p> : null}
                        {contactOptions.length > 0 ? (
                          <div className="google-agenda-contact-list">
                            {contactOptions.map((option) => {
                              const email = contactOptionAgendaEmail(option)
                              const contactLink = contactOptionAgendaLink(option, email)
                              return (
                                <button key={`contact-option-${option.hektor_contact_id}`} className="google-agenda-contact-button" type="button" onClick={() => contactLink && handleAddAgendaInvitee(contactLink)} disabled={!contactLink}>
                                  <strong>{mandantContactOptionTitle(option)}</strong>
                                  <span>{email || option.phone_primary || option.phone_secondary || 'Email absent'}</span>
                                  <small>{mandantContactOptionSubtitle(option)}</small>
                                </button>
                              )
                            })}
                          </div>
                        ) : contactSearch.trim().length >= (/^\d+$/.test(contactSearch.trim()) ? 1 : 3) && !contactSearchLoading ? <p className="empty-state">Aucun contact trouve dans le perimetre agence/negociateur.</p> : null}
                      </div>
                    </div>
                  </div>
                  <label className="filter-field google-agenda-field-wide">
                    <span>Description</span>
                    <textarea className="inline-textarea" value={description} onChange={(inputEvent) => setDescription(inputEvent.target.value)} placeholder={isEditingGoogleAgendaEvent ? 'Vide = description Google conservee' : undefined} />
                  </label>
                  {!canUseCalendarEmail ? <p className="google-agenda-error">Agenda Google Workspace requis.</p> : null}
                  {message ? <p className="google-agenda-success">{message}</p> : null}
                  {error ? <p className="google-agenda-error">{error}</p> : null}
                  {availability ? (
                    <div className={availability.isAvailable ? 'google-agenda-success' : 'google-agenda-warning'}>
                      <strong>{availability.isAvailable ? 'Disponible sur ce creneau.' : `Conflit agenda : ${availability.busyCount ?? availabilityBusy.length} creneau occupe.`}</strong>
                      {!availability.isAvailable && availabilityBusy.length > 0 ? (
                        <span>{availabilityBusy.slice(0, 3).map((slot) => `${formatDateTime(slot.start)} - ${formatDateTime(slot.end)}`).join(' | ')}</span>
                      ) : null}
                    </div>
                  ) : null}
                  <div className="modal-actions google-agenda-actions">
                    {isEditingGoogleAgendaEvent ? (
                      <button className="ghost-button button-subtle" type="button" onClick={resetGoogleAgendaForm} disabled={pending}>
                        Annuler
                      </button>
                    ) : null}
                    <button className="ghost-button button-subtle" type="button" onClick={() => void handleCheckGoogleAgendaAvailability()} disabled={availabilityPending || pending || !canCheckAvailability}>
                      {availabilityPending ? 'Verification...' : 'Verifier dispo'}
                    </button>
                    <button className="ghost-button button-primary" type="submit" disabled={pending || !canUseCalendarEmail || !canSubmitGoogleAgendaEvent}>
                      {pending ? (isEditingGoogleAgendaEvent ? 'Enregistrement...' : 'Creation...') : isEditingGoogleAgendaEvent ? 'Enregistrer le RDV' : 'Creer RDV Google'}
                    </button>
                  </div>
                </form>
              </section>
              <section className="google-agenda-panel google-agenda-day-panel">
                <div className="google-agenda-panel-head google-agenda-day-head">
                  <div>
                    <span>Agenda negociateur</span>
                    <strong>{agendaMode === 'week' ? 'Occupation semaine' : 'Occupation journee'}</strong>
                    <small>{googleAgendaRangeLabel(agendaDate, agendaMode)}</small>
                  </div>
                  <div className="google-agenda-day-actions">
                    <div className="google-agenda-view-toggle" role="group" aria-label="Vue agenda">
                      <button className={agendaMode === 'day' ? 'is-active' : ''} type="button" onClick={() => { setAgendaMode('day'); setDayAvailability(null); setPeriodLinkedEvents([]) }}>
                        Jour
                      </button>
                      <button className={agendaMode === 'week' ? 'is-active' : ''} type="button" onClick={() => { setAgendaMode('week'); setDayAvailability(null); setPeriodLinkedEvents([]) }}>
                        Semaine
                      </button>
                    </div>
                    <input value={agendaDate} onChange={(inputEvent) => { setAgendaDate(inputEvent.target.value); setDayAvailability(null); setPeriodLinkedEvents([]) }} type="date" />
                    <button className="ghost-button button-subtle" type="button" onClick={() => void handleLoadGoogleAgendaPeriod()} disabled={dayAvailabilityPending || !canUseCalendarEmail}>
                      {dayAvailabilityPending ? 'Chargement...' : 'Actualiser'}
                    </button>
                  </div>
                </div>
                {dayAvailability ? (
                  <>
                    <div className="google-agenda-suggestions">
                      <span className="detail-label">{agendaMode === 'week' ? 'Creneaux proposes sur la semaine' : 'Creneaux proposes'}</span>
                      {suggestedWindows.length > 0 ? (
                        <div className="google-agenda-suggestion-list">
                          {suggestedWindows.map((slot, index) => (
                            <button key={`suggestion-${slot.start}-${slot.end}`} className="google-agenda-suggestion" type="button" onClick={() => handleUseGoogleAgendaWindow(slot)}>
                              <strong>{index === 0 ? 'Meilleur creneau' : `Option ${index + 1}`}</strong>
                              <span>{formatDateTime(slot.start)} - {formatDateTime(slot.end)}</span>
                            </button>
                          ))}
                        </div>
                      ) : <p className="empty-state">Aucun creneau assez long pour la duree choisie.</p>}
                    </div>
                    <div className={`google-agenda-period-grid is-${agendaMode}`}>
                      {agendaDayPlans.map((plan) => (
                        <article key={`agenda-period-${plan.day}`} className="google-agenda-period-day">
                          <div className="google-agenda-period-day-head">
                            <strong>{plan.label}</strong>
                            <span>{plan.events.length} RDV GTI - {plan.busy.length} occupe</span>
                          </div>
                          <div className="google-agenda-period-section">
                            <span className="detail-label">RDV GTI</span>
                            {plan.events.length > 0 ? (
                              <div className="google-agenda-period-items">
                                {plan.events.map((item) => (
                                  <button key={`period-gti-${plan.day}-${item.id}`} className="google-agenda-period-event" type="button" onClick={() => handleEditGoogleAgendaEvent(item)}>
                                    <strong>{formatDateTime(item.starts_at)} - {formatDateTime(item.ends_at)}</strong>
                                    <span>{item.summary}</span>
                                  </button>
                                ))}
                              </div>
                            ) : <p className="empty-state">Aucun RDV GTI lie.</p>}
                          </div>
                          <div className="google-agenda-period-section">
                            <span className="detail-label">Google occupe</span>
                            <div className="google-agenda-day-slots">
                              {plan.busy.length > 0 ? plan.busy.map((slot) => (
                                <article key={`busy-${plan.day}-${slot.start}-${slot.end}`} className="google-agenda-day-slot is-busy">
                                  <strong>{formatDateTime(slot.start)} - {formatDateTime(slot.end)}</strong>
                                  <span>Occupe Google</span>
                                </article>
                              )) : <p className="empty-state">Aucun creneau occupe.</p>}
                            </div>
                          </div>
                          <div className="google-agenda-period-section">
                            <span className="detail-label">Libres</span>
                            <div className="google-agenda-day-slots">
                              {plan.free.length > 0 ? plan.free.map((slot) => (
                                <article key={`free-${plan.day}-${slot.start}-${slot.end}`} className="google-agenda-day-slot is-free">
                                  <div>
                                    <strong>{formatDateTime(slot.start)} - {formatDateTime(slot.end)}</strong>
                                    <span>{minutesBetweenWindow(slot)} min libres</span>
                                  </div>
                                  <button className="ghost-button button-subtle" type="button" onClick={() => handleUseGoogleAgendaWindow(slot)}>
                                    Utiliser
                                  </button>
                                </article>
                              )) : <p className="empty-state">Aucun creneau libre entre 08:00 et 19:00.</p>}
                            </div>
                          </div>
                        </article>
                      ))}
                    </div>
                  </>
                ) : <p className="empty-state">{dayAvailabilityPending ? 'Chargement agenda...' : 'Clique sur Actualiser pour voir les plages libres et occupees.'}</p>}
              </section>
              {activeEvents.length > 0 || loading ? (
              <section className="google-agenda-panel google-agenda-links-panel">
                <div className="google-agenda-panel-head">
                  <span>Annonce GTI</span>
                  <strong>Rendez-vous deja lies</strong>
                </div>
                {activeEvents.length > 0 ? (
                  <div className="google-agenda-event-list">
                    {activeEvents.map((item) => {
                      const eventInvitees = Array.isArray(item.attendees_json) ? item.attendees_json : []
                      const eventInviteeContacts = googleAgendaEventInviteeContacts(item)
                      const visitVoucherIssue = visitVoucherMissingReason(item)
                      return (
                        <article key={item.id} className="google-agenda-event-card">
                          <div>
                            <strong>{item.summary}</strong>
                            <span>{formatDateTime(item.starts_at)} - {formatDateTime(item.ends_at)}</span>
                            <span>{item.google_calendar_email}</span>
                            {item.location ? <span>{item.location}</span> : null}
                            {eventInvitees.length > 0 ? <span>Invites : {eventInvitees.join(', ')}</span> : null}
                            {eventInviteeContacts.length > 0 ? (
                              <div className="google-agenda-event-contact-row">
                                {eventInviteeContacts.map((contactLink) => contactLink.hektorContactId && props.onOpenContact ? (
                                  <button key={`event-contact-${item.id}-${contactLink.email}`} type="button" onClick={() => props.onOpenContact?.(contactLink.hektorContactId as string)}>
                                    <strong>{contactLink.label || contactLink.email}</strong>
                                    <span>Contact {contactLink.hektorContactId}</span>
                                  </button>
                                ) : (
                                  <span key={`event-contact-${item.id}-${contactLink.email}`}>{contactLink.label || contactLink.email}</span>
                                ))}
                              </div>
                            ) : null}
                            {visitVoucherIssue ? <span>{visitVoucherIssue}</span> : null}
                          </div>
                          <div className="google-agenda-event-actions">
                            {item.google_html_link ? (
                              <a className="ghost-button button-subtle" href={item.google_html_link} target="_blank" rel="noreferrer">Ouvrir</a>
                            ) : null}
                            {canPrintVisitVoucher(item) ? (
                              <button className="ghost-button button-primary" type="button" onClick={() => void handlePrintGoogleAgendaVisitVoucher(item)} disabled={pending || deletingId === item.id || printingId === item.id}>
                                {printingId === item.id ? 'Preparation...' : 'Bon de visite'}
                              </button>
                            ) : null}
                            <button className="ghost-button button-subtle" type="button" onClick={() => handleEditGoogleAgendaEvent(item)} disabled={pending || deletingId === item.id}>
                              Modifier
                            </button>
                            <button className="ghost-button button-subtle" type="button" onClick={() => void handleDeleteGoogleAgendaEvent(item)} disabled={deletingId === item.id}>
                              {deletingId === item.id ? 'Suppression...' : 'Supprimer'}
                            </button>
                          </div>
                        </article>
                      )
                    })}
                  </div>
                ) : <p className="empty-state">Chargement des RDV Google...</p>}
              </section>
              ) : null}
            </div>
            {contactCreateOpen && props.canManageContacts ? (
              <ContactWorkflowModal
                title="Nouveau contact"
                eyebrow="Creation Hektor"
                summary="Creation via le workflow contact existant, puis ajout aux invites si un email est renseigne."
                tone="create"
                onClose={() => setContactCreateOpen(false)}
              >
                <HektorContactIdentityForm
                  mode="create"
                  hektorUserEmail={props.hektorUserEmail}
                  hektorUserId={props.hektorUserId}
                  hektorNegotiators={props.hektorNegotiators}
                  profileRole={props.profileRole}
                  sessionEmail={props.sessionEmail}
                  onCancel={() => setContactCreateOpen(false)}
                  onJobCreated={props.onHektorActionJobCreated}
                  onContactInputCreated={handleGoogleAgendaContactJobCreated}
                />
              </ContactWorkflowModal>
            ) : null}
          </section>
        </div>,
        document.body,
      ) : null}
    </section>
  )
}

function AppointmentAnnonceSection(props: {
  dossier: Dossier | null
  detail: DossierDetailPayload
}) {
  const appointmentUrl = buildAppointmentAnnonceUrl(props.dossier, props.detail)
  const requests = parseAppointmentRequests(props.detail)
  const events = parseAppointmentRequestEvents(props.detail)
  const appointmentEmail = safeText(props.detail.appointment_negociateur_email) || props.dossier?.negociateur_email || '-'
  const appointmentNegociateurId = props.detail.appointment_negociateur_id ?? props.dossier?.commercial_id ?? '-'

  return (
    <section className="detail-section detail-appointment-section">
      <div className="section-header"><DetailSectionTitle icon="contact" title="Rendez-vous annonce" /></div>
      <div className="detail-stack">
        <article className="detail-card">
          <span className="detail-label">Ciblage QR</span>
          <div className="info-grid">
            <InfoCard label="Mode" value="QR annonce vitrine" />
            <InfoCard label="ID annonce" value={props.dossier?.hektor_annonce_id ?? '-'} />
            <InfoCard label="Negociateur" value={props.dossier?.commercial_nom ?? '-'} />
            <InfoCard label="ID nego" value={appointmentNegociateurId} />
            <InfoCard label="Email nego" value={appointmentEmail} />
            <InfoCard label="Agence" value={props.dossier?.agence_nom ?? '-'} />
          </div>
          <div className="detail-rich-copy">
            <strong>URL publique cible</strong>
            <p>{appointmentUrl ?? 'Aucune URL publique configuree pour le moment.'}</p>
          </div>
        </article>
        <article className="detail-card">
          <span className="detail-label">Demandes recues</span>
          {requests.length > 0 ? (
            <div className="timeline-list">
              {requests.map((item, index) => (
                <article key={String(item.id ?? index)} className="timeline-card">
                  <strong>{item.client_nom ?? 'Client sans nom'} · {appointmentStatusLabel(item.status)}</strong>
                  <span>{formatDate(item.requested_start_at)}{item.requested_end_at ? ` â†’ ${formatDate(item.requested_end_at)}` : ''}</span>
                  <span>{item.client_telephone ?? item.client_email ?? '-'}</span>
                  <p>{item.message ?? 'Sans message client.'}</p>
                </article>
              ))}
            </div>
          ) : <p className="empty-state">Aucune demande RDV stockee pour cette annonce pour le moment.</p>}
        </article>
        <article className="detail-card">
          <span className="detail-label">Historique RDV</span>
          {events.length > 0 ? (
            <div className="timeline-list">
              {events.map((item, index) => (
                <article key={String(item.id ?? index)} className="timeline-card">
                  <strong>{item.event_label ?? item.event_type ?? 'Evenement RDV'}</strong>
                  <span>{formatDate(item.created_at)}</span>
                  <span>{item.actor_name ?? 'Systeme'}</span>
                  <p>{item.payload_json ?? 'Sans detail supplementaire.'}</p>
                </article>
              ))}
            </div>
          ) : <p className="empty-state">Historique RDV vide tant que le module de demandes n'est pas encore stocke en base.</p>}
        </article>
      </div>
    </section>
  )
}

