function contactJsonList(value: unknown) {
  if (Array.isArray(value)) return value.map((item) => String(item).trim()).filter(Boolean)
  return parseJson<string[]>(typeof value === 'string' ? value : null, []).map((item) => String(item).trim()).filter(Boolean)
}

type ContactTone = 'buyer' | 'owner' | 'mandate' | 'notary' | 'mixed' | 'search' | 'default'

function isBuyerRole(value: string) {
  return value === 'acquereur' || value.startsWith('acquereur_')
}

function contactToneFromRoles(roles: string[], contact?: Pick<AppContact, 'active_search_count' | 'total_search_count'> | null): ContactTone {
  const hasBuyer = roles.some(isBuyerRole)
  const hasOwner = roles.includes('proprietaire')
  const hasMandate = roles.includes('mandant')
  const hasNotary = roles.some((role) => role.startsWith('notaire'))
  const typedCount = [hasBuyer, hasOwner, hasMandate, hasNotary].filter(Boolean).length
  if (typedCount > 1) return 'mixed'
  if (hasBuyer) return 'buyer'
  if (hasOwner) return 'owner'
  if (hasMandate) return 'mandate'
  if (hasNotary) return 'notary'
  if ((contact?.active_search_count ?? 0) > 0 || (contact?.total_search_count ?? 0) > 0) return 'search'
  return 'default'
}

// ----- Annuaire des contacts (refonte maquette) : derivations visuelles -----
// Categories metier NON exclusives : un contact peut cumuler un cote vente ET un
// cote achat (max une par cote => 0, 1 ou 2 categories).
//  - Cote vente  : Mandant (mandat actif) > Vendeur (role `proprietaire`, lie a une transaction)
//  - Cote achat  : Acquereur (recherche active) > Acheteur (`acquereur_vente`, achat conclu)
// NB : `proprietaire` est un VENDEUR (transaction), libelle "Vendeur" pour ne pas
// le confondre avec Mandant ; le role technique et les filtres serveur restent inchanges.
type ContactDirectoryType = 'vendeur' | 'mandant' | 'acquereur' | 'acheteur' | 'autre'
const contactDirectoryTypeLabel: Record<ContactDirectoryType, string> = {
  vendeur: 'Vendeur',
  mandant: 'Mandant',
  acquereur: 'Acquéreur',
  acheteur: 'Acheteur',
  autre: 'Contact',
}
function contactDirectoryCategories(roles: string[]): ContactDirectoryType[] {
  const out: ContactDirectoryType[] = []
  const sell: ContactDirectoryType | null = roles.includes('mandant') ? 'mandant' : roles.includes('proprietaire') ? 'vendeur' : null
  const hasActiveBuyer = roles.some((role) => isBuyerRole(role) && role !== 'acquereur_vente')
  const buy: ContactDirectoryType | null = hasActiveBuyer ? 'acquereur' : roles.includes('acquereur_vente') ? 'acheteur' : null
  if (sell) out.push(sell)
  if (buy) out.push(buy)
  return out
}
// Badge "Qualite" = fiabilite de la fiche (completeness_score). En prod c'est un
// score ENTIER 0..8 (nb de champs cles renseignes), verifie sur app_contacts_current.
// Seuils : Fort >=6, Moyen 4-5, Critique 1-3, N/D = 0/absent.
function contactQualityTier(contact: Pick<AppContact, 'completeness_score'>): { tier: 'fort' | 'moyen' | 'critique' | 'nd'; label: string } {
  const score = Number(contact.completeness_score ?? 0)
  if (!(score > 0)) return { tier: 'nd', label: 'N/D' }
  if (score >= 6) return { tier: 'fort', label: 'Fort' }
  if (score >= 4) return { tier: 'moyen', label: 'Moyen' }
  return { tier: 'critique', label: 'Critique' }
}
function contactHasDuplicateRisk(contact: Pick<AppContact, 'duplicate_max_severity' | 'duplicate_group_count'>): boolean {
  const severity = String(contact.duplicate_max_severity ?? '').toLowerCase()
  return severity === 'high' || severity === 'critical' || Number(contact.duplicate_group_count ?? 0) > 0
}

function contactToneLabel(tone: ContactTone) {
  if (tone === 'buyer') return 'Acquereur'
  if (tone === 'owner') return 'Proprietaire'
  if (tone === 'mandate') return 'Mandant'
  if (tone === 'notary') return 'Notaire'
  if (tone === 'mixed') return 'Multi-role'
  if (tone === 'search') return 'Recherche'
  return 'Contact'
}

function contactToneBadgeLabel(tone: ContactTone) {
  if (tone === 'buyer') return 'Acquereur'
  if (tone === 'owner') return 'Vendeur'
  if (tone === 'mandate') return 'Mandant'
  if (tone === 'notary') return 'Notaire'
  if (tone === 'mixed') return 'Mixte'
  if (tone === 'search') return 'Recherche'
  return 'Contact'
}

function contactToneIcon(tone: ContactTone): DetailIconKey {
  if (tone === 'search') return 'visibility'
  if (tone === 'mandate' || tone === 'notary') return 'mandate'
  return 'contact'
}

function contactRoleBadges(roles: string[]) {
  const normalized = new Set<string>()
  roles.forEach((role) => {
    if (isBuyerRole(role)) normalized.add('acquereur')
    else normalized.add(role)
  })
  return Array.from(normalized)
}

function contactTypologyBadges(contact: AppContact) {
  const roles = contactJsonList(contact.relation_roles_json)
  const typologies = contactJsonList(contact.typologies_json)
  return Array.from(new Set([...contactRoleBadges(roles), ...typologies])).filter(Boolean)
}

function contactRoleChipClass(value: string) {
  const normalized = value.normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase()
  if (isBuyerRole(normalized) || normalized === 'acquereur') return 'contact-role-chip is-buyer'
  if (normalized === 'proprietaire') return 'contact-role-chip is-owner'
  if (normalized === 'mandant') return 'contact-role-chip is-mandate'
  if (normalized.startsWith('notaire')) return 'contact-role-chip is-notary'
  if (normalized === 'recherche' || normalized.includes('search')) return 'contact-role-chip is-search'
  return 'contact-role-chip'
}

function ContactTypeMark({ contact, compact = false }: { contact: AppContact; compact?: boolean }) {
  const roles = contactJsonList(contact.relation_roles_json)
  const tone = contactToneFromRoles(roles, contact)
  const label = contactToneLabel(tone)
  return (
    <span className={`contact-type-mark is-${tone} ${compact ? 'is-compact' : ''}`} title={label} aria-label={label}>
      <span className="contact-type-mark-icon" aria-hidden="true"><DetailIcon type={contactToneIcon(tone)} /></span>
      <span className="contact-type-mark-label">{contactToneBadgeLabel(tone)}</span>
    </span>
  )
}

function contactArchiveLabel(contact: Pick<AppContact, 'archive'>) {
  return contact.archive === true || contact.archive === 1 || contact.archive === '1' ? 'Archive' : 'Actif'
}

function contactSeverityLabel(value: AppContact['duplicate_max_severity']) {
  if (value === 'critical') return 'Critique'
  if (value === 'high') return 'Fort'
  if (value === 'medium') return 'Moyen'
  if (value === 'low') return 'Faible'
  return 'Aucun'
}

function contactDuplicateTone(value: AppContact['duplicate_max_severity']) {
  return value ? `is-${value}` : 'is-none'
}

function contactDirectoryRoleLabel(value: string) {
  const normalized = value.normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase()
  if (normalized === 'proprietaire') return 'Proprietaire'
  if (normalized === 'mandant') return 'Mandant'
  if (normalized === 'acquereur') return 'Acquereur'
  if (normalized === 'acquereur_offre') return 'Acquereur offre'
  if (normalized === 'acquereur_compromis') return 'Acquereur compromis'
  if (normalized === 'acquereur_vente') return 'Acquereur vente'
  if (normalized === 'notaire_entree') return 'Notaire entree'
  if (normalized === 'notaire_sortie') return 'Notaire sortie'
  return value || 'Contact'
}

function contactBool(value: unknown) {
  return value === true || value === 1 || value === '1'
}

function contactSearchTypes(value: AppContactSearch['types_json']) {
  if (value && typeof value === 'object' && !Array.isArray(value)) {
    return Object.entries(value)
      .filter(([, optionValue]) => {
        const text = String(optionValue ?? '').trim().toLowerCase()
        return optionValue === true || optionValue === 1 || text === '1' || Boolean(text && text !== '0' && text !== 'false')
      })
      .map(([key, optionValue]) => {
        if (typeof optionValue === 'string' && optionValue.trim() && optionValue !== '1') return optionValue.trim()
        return key
      })
      .filter(Boolean)
  }
  const parsed = parseJson<Record<string, unknown>>(typeof value === 'string' ? value : null, {})
  return contactSearchTypes(parsed)
}

function contactRangeLabel(label: string, min?: string | null, max?: string | null, suffix = '') {
  // Une borne valant 0 (ou vide) = non renseignee -> on ne l'affiche pas.
  const clean = (value?: string | null) => {
    const text = safeText(value)
    if (!text) return ''
    return /^0+([.,]0+)?$/.test(text.trim()) ? '' : text
  }
  const fmt = (text: string) => {
    const n = Number(text.replace(/[\s ]/g, '').replace(',', '.'))
    return Number.isFinite(n) ? n.toLocaleString('fr-FR') : text
  }
  const left = clean(min)
  const right = clean(max)
  if (!left && !right) return null
  const value = left && right
    ? `${fmt(left)} – ${fmt(right)}${suffix}`
    : left
      ? `min ${fmt(left)}${suffix}`
      : `max ${fmt(right)}${suffix}`
  return `${label}: ${value}`
}

function contactSearchCriteriaLabels(search: AppContactSearch) {
  return [
    contactRangeLabel('Budget', search.prix_min, search.prix_max, ' €'),
    contactRangeLabel('Surface', search.surface_min, search.surface_max, ' m²'),
    contactRangeLabel('Pièces', search.pieces_min, search.pieces_max),
    contactRangeLabel('Chambres', search.chambre_min, search.chambre_max),
    contactRangeLabel('Terrain', search.surface_terrain_min, search.surface_terrain_max, ' m²'),
  ].filter(Boolean) as string[]
}

function contactTransactionLabel(relation: AppContactRelation) {
  const type = safeText(relation.transaction_type)
  const id = safeText(relation.transaction_id)
  if (!type && !id) return null
  return [type || 'transaction', id ? `#${id}` : null, safeText(relation.transaction_state) || null].filter(Boolean).join(' ')
}

function contactIdentityInputFromContact(contact: AppContact, hektorUserEmail?: string | null, hektorUserId?: string | null): HektorContactIdentityInput {
  const typologies = contactJsonList(contact.typologies_json).map(normalizeContactText)
  const roles = contactJsonList(contact.relation_roles_json).map(normalizeContactText)
  const allTags = [...typologies, ...roles]
  const inferredKind = allTags.some((value) => value.includes('partenaire') || value.includes('notaire'))
    ? 'partenaire'
    : allTags.some((value) => value.includes('locataire'))
      ? 'locataire'
      : allTags.some((value) => value.includes('proprietaire') || value.includes('mandant'))
        ? 'proprietaire'
        : 'acquereur'
  return {
    civility: contact.civilite ?? '',
    lastName: contact.nom || contact.display_name || '',
    firstName: contact.prenom ?? '',
    companyName: '',
    legalForm: '',
    siret: '',
    partnerJobId: '',
    website: '',
    spouseLastName: '',
    spouseFirstName: '',
    spouseEmail: '',
    spousePhone: '',
    spouseAddress: '',
    spousePostalCode: '',
    spouseCity: '',
    email: contact.email ?? '',
    phone: contact.phone_primary ?? '',
    phoneSecondary: contact.phone_secondary ?? '',
    postalCode: contact.code_postal ?? '',
    city: contact.ville ?? '',
    address: contact.adresse ?? '',
    birthDate: contact.birth_date ?? '',
    birthPlace: contact.birth_place ?? '',
    maritalStatus: contact.marital_status ?? '',
    contactKind: inferredKind,
    personType: 'personne_seule',
    sendRgpdEmail: true,
    crmMandateSummaryEnabled: null,
    crmMandateExpirationEnabled: null,
    crmBirthdayEnabled: null,
    hektorUserEmail: hektorUserEmail ?? contact.negociateur_email ?? null,
    hektorUserId: hektorUserId ?? null,
    hektorUserLabel: null,
    hektorNegotiatorId: null,
    hektorAgencyId: null,
    hektorAgencyUserId: null,
    hektorAgencyLabel: null,
  }
}

